全局过滤器@Component@Slf4jpublic class AuthGlobalFilter implements GlobalFilter, Ordered &#123;    @Override    public Mono&lt;Void&gt; filter(ServerWebExchange exchange, GatewayFilterChain chain) &#123;        String path = exchange.getRequest().getURI().getPath();        // 白名单路径放行        if (path.contains(&quot;/auth/login&quot;) || path.contains(&quot;/auth/register&quot;)) &#123;            return chain.filter(exchange);        &#125;        // 检查Token        String token = exchange.getRequest().getHeaders().getFirst(&quot;Authorization&quot;);        if (token == null || !validateToken(token)) &#123;            exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);            return exchange.getResponse().setComplete();        &#125;        // 传递用户信息        String userId = parseUserId(token);        ServerHttpRequest request = exchange.getRequest().mutate()            .header(&quot;X-User-Id&quot;, userId)            .build();        return chain.filter(exchange.mutate().request(request).build());    &#125;    @Override    public int getOrder() &#123;        return -1;    &#125;&#125;

