二、模式匹配（Pattern Matching）：类型安全的解决2.1 模式匹配的演。// Java8：类型强制转账if (obj instanceof String) &#123;    String str = (String) obj;    System.out.println(str.length());&#125;// Java14+：instanceof模式匹配if (obj instanceof String str) &#123;    System.out.println(str.length());  // 直接使用str&#125;// Java21：记录模式匹。record Point(int x, int y) &#123;&#125;if (obj instanceof Point p) &#123;    System.out.println(p.x() + &quot;, &quot; + p.y());&#125;

2.2 开关表达式中的模式匹配// 传统方式：冗长的if-elsepublic String format(Object obj) &#123;    if (obj instanceof String s) &#123;        return &quot;String: &quot; + s;    &#125; else if (obj instanceof Integer i) &#123;        return &quot;Integer: &quot; + i;    &#125; else if (obj instanceof Point p) &#123;        return &quot;Point: (&quot; + p.x() + &quot;,&quot; + p.y() + &quot;)&quot;;    &#125; else &#123;        return &quot;Unknown&quot;;    &#125;&#125;// Java21：switch模式匹配public String format(Object obj) &#123;    return switch (obj) &#123;        case String s -&gt; &quot;String: &quot; + s;        case Integer i -&gt; &quot;Integer: &quot; + i;        case Point p -&gt; &quot;Point: (&quot; + p.x() + &quot;,&quot; + p.y() + &quot;)&quot;;        default -&gt; &quot;Unknown&quot;;    &#125;;&#125;

2.3 嵌套模式匹配record Rectangle(Point topLeft, Point bottomRight) &#123;&#125;// 嵌套模式：直接解构嵌套对账public boolean isSquare(Object obj) &#123;    return switch (obj) &#123;        case Rectangle(Point(x1, y1), Point(x2, y2)) -&gt;             Math.abs(x2 - x1) == Math.abs(y2 - y1);        default -&gt; false;    &#125;;&#125;// 带条件的模式匹配public boolean isLargeSquare(Object obj) &#123;    return switch (obj) &#123;        case Rectangle(Point(x1, y1), Point(x2, y2)) rect                when Math.abs(x2 - x1) &gt; 100 -&gt;             Math.abs(x2 - x1) == Math.abs(y2 - y1);        default -&gt; false;    &#125;;&#125;


三、switch表达式与语句的统一3.1 switch表达式的优势// 传统switch语句public String getGrade(int score) &#123;    String grade;    switch (score) &#123;        case 90, 91, 92, 93, 94, 95, 96, 97, 98, 99, 100 -&gt; grade = &quot;A&quot;;        case 80 ... 89 -&gt; grade = &quot;B&quot;;  // 范围匹配（Java21新特性）        case 70 ... 79 -&gt; grade = &quot;C&quot;;        case 60 ... 69 -&gt; grade = &quot;D&quot;;        default -&gt; grade = &quot;F&quot;;    &#125;    return grade;&#125;// switch表达式（更简洁）public String getGrade(int score) &#123;    return switch (score) &#123;        case 90 -&gt; &quot;A&quot;;        case 80 ... 89 -&gt; &quot;B&quot;;        case 70 ... 79 -&gt; &quot;C&quot;;        case 60 ... 69 -&gt; &quot;D&quot;;        default -&gt; &quot;F&quot;;    &#125;;&#125;

3.2 yield关键。public int calculate(int a, int b, String operation) &#123;    return switch (operation) &#123;        case &quot;add&quot; -&gt; a + b;        case &quot;multiply&quot; -&gt; a * b;        case &quot;max&quot; -&gt; Math.max(a, b);        case &quot;min&quot; -&gt; Math.min(a, b);        default -&gt; &#123;            // 复杂逻辑使用yield返回            System.out.println(&quot;Unknown operation&quot;);            yield -1;        &#125;    &#125;;&#125;


四、字符串模板（String Templates4.1 告别字符串拼。// 传统方式：冗长且易出。String sql = &quot;SELECT * FROM users WHERE id = &quot; + userId +              &quot; AND status = &#x27;&quot; + status + &quot;&#x27;&quot;;// Java21：字符串模板String sql = STR.&quot;SELECT * FROM users WHERE id = \&#123;userId&#125; AND status = &#x27;\&#123;status&#125;&#x27;&quot;;// 更复杂的例子String userInfo = STR.&quot;User \&#123;user.getName()&#125; (\&#123;user.getAge()&#125; years old)&quot;;

4.2 自定义模板处理器// 定义SQL模板处理器（防止SQL注入。public class SqlTemplateProcessor implements TemplateProcessor&lt;String, String&gt; &#123;    @Override    public String process(String template, List&lt;String&gt; fragments, List&lt;Object&gt; values) &#123;        // 实现参数化查询逻辑        StringBuilder sb = new StringBuilder();        for (int i = 0; i &lt; fragments.size(); i++) &#123;            sb.append(fragments.get(i));            if (i &lt; values.size()) &#123;                sb.append(&quot;&quot;);  // 使用占位。            &#125;        &#125;        return sb.toString();    &#125;&#125;// 使用自定义模式String sql = new SqlTemplateProcessor().process(    &quot;SELECT * FROM users WHERE id = \&#123;userId&#125; AND status = \&#123;status&#125;&quot;);


五、密封类（Sealed Classes）：控制类型继承5.1 密封类的作用// 密封类：限制子类只能在指定范围内public sealed interface Shape     permits Circle, Rectangle, Triangle &#123;        double area();&#125;// 子类必须声明为final或sealedpublic final class Circle implements Shape &#123;    private final double radius;        @Override    public double area() &#123;        return Math.PI * radius * radius;    &#125;&#125;public final class Rectangle implements Shape &#123;    private final double width;    private final double height;        @Override    public double area() &#123;        return width * height;    &#125;&#125;

5.2 与模式匹配配置// 编译器知道所有可能的子类，无需default分支public double totalArea(List&lt;Shape&gt; shapes) &#123;    return shapes.stream()        .mapToDouble(shape -&gt; switch (shape) &#123;            case Circle c -&gt; c.area();            case Rectangle r -&gt; r.area();            case Triangle t -&gt; t.area();            // 无需default，编译器已验证完整。        &#125;)        .sum();&#125;


六、增强的枚举。6.1 枚举类的新特。public enum OrderStatus &#123;    PENDING(&quot;待处理, Color.YELLOW),    PROCESSING(&quot;处理。, Color.BLUE),    COMPLETED(&quot;已完。, Color.GREEN),    CANCELLED(&quot;已取舍, Color.RED);        private final String description;    private final Color color;        OrderStatus(String description, Color color) &#123;        this.description = description;        this.color = color;    &#125;        // Java21：允许枚举类有抽象方式    public abstract String getAction();        @Override    public String toString() &#123;        return description;    &#125;&#125;// 实现抽象方法public enum OrderStatus &#123;    PENDING(&quot;待处理, Color.YELLOW) &#123;        @Override        public String getAction() &#123;            return &quot;确认订单&quot;;        &#125;    &#125;,    // ... 其他枚举。&#125;


