2. 全局异常处理的好。// →没有全局异常处理@GetMapping(&quot;/user/&#123;id&#125;&quot;)public ResponseEntity&lt;User&gt; getUser(@PathVariable Long id) &#123;    User user = userService.findById(id);    if (user == null) &#123;        throw new RuntimeException(&quot;用户不存。);  // 返回堆栈信息    &#125;    return ResponseEntity.ok(user);&#125;// →有全局异常处理@GetMapping(&quot;/user/&#123;id&#125;&quot;)public ResponseEntity&lt;User&gt; getUser(@PathVariable Long id) &#123;    User user = userService.findById(id);    if (user == null) &#123;        throw new BusinessException(404, &quot;用户不存。);  // 返回统一格式    &#125;    return ResponseEntity.ok(user);&#125;

3. 完整的全局异常处理。@RestControllerAdvice@Slf4jpublic class GlobalExceptionHandler &#123;        /**     * 处理业务异常     */    @ExceptionHandler(BusinessException.class)    public ResponseEntity&lt;ErrorResponse&gt; handleBusinessException(BusinessException ex) &#123;        log.warn(&quot;业务异常: &#123;&#125;&quot;, ex.getMessage());        return ResponseEntity.status(ex.getCode())                .body(new ErrorResponse(ex.getCode(), ex.getMessage(), null));    &#125;        /**     * 处理参数校验异常     */    @ExceptionHandler(MethodArgumentNotValidException.class)    public ResponseEntity&lt;ErrorResponse&gt; handleValidationException(            MethodArgumentNotValidException ex) &#123;                String detail = ex.getBindingResult()                .getFieldErrors()                .stream()                .map(error -&gt; error.getField() + &quot;: &quot; + error.getDefaultMessage())                .collect(Collectors.joining(&quot;; &quot;));                log.warn(&quot;参数校验失败: &#123;&#125;&quot;, detail);        return ResponseEntity.badRequest()                .body(new ErrorResponse(400, &quot;参数校验失败&quot;, detail));    &#125;        /**     * 处理参数格式异常（如URL参数类型错误。     */    @ExceptionHandler(TypeMismatchException.class)    public ResponseEntity&lt;ErrorResponse&gt; handleTypeMismatchException(            TypeMismatchException ex) &#123;                log.warn(&quot;参数格式错误: &#123;&#125;&quot;, ex.getMessage());        return ResponseEntity.badRequest()                .body(new ErrorResponse(400, &quot;参数格式错误&quot;, null));    &#125;        /**     * 处理其他未知异常     */    @ExceptionHandler(Exception.class)    public ResponseEntity&lt;ErrorResponse&gt; handleException(Exception ex) &#123;        log.error(&quot;系统异常&quot;, ex);  // 记录完整堆栈        return ResponseEntity.status(500)                .body(new ErrorResponse(500, &quot;系统内部错误，请稍后重试&quot;, null));    &#125;&#125;// 统一错误响应@Datapublic class ErrorResponse &#123;    private Integer code;    private String message;    private String detail;        public ErrorResponse(Integer code, String message, String detail) &#123;        this.code = code;        this.message = message;        this.detail = detail;    &#125;&#125;// 自定义业务异。@Datapublic class BusinessException extends RuntimeException &#123;    private Integer code;        public BusinessException(Integer code, String message) &#123;        super(message);        this.code = code;    &#125;&#125;


