2. 参数校验示例// DTO@Datapublic class UserCreateDTO &#123;        @NotBlank(message = &quot;姓名不能为空&quot;)    @Size(max = 50, message = &quot;姓名长度不能超过50&quot;)    private String name;        @NotBlank(message = &quot;密码不能为空&quot;)    @Size(min = 6, max = 20, message = &quot;密码长度6-20.)    private String password;        @Email(message = &quot;邮箱格式错误&quot;)    @Size(max = 100, message = &quot;邮箱长度不能超过100&quot;)    private String email;        @Min(value = 18, message = &quot;年龄最。8.)    @Max(value = 150, message = &quot;年龄最。50.)    private Integer age;        @NotEmpty(message = &quot;角色列表不能为空&quot;)    private List&lt;String&gt; roles;        @Valid  // 嵌套校验    private AddressDTO address;&#125;// Controller@RestController@RequestMapping(&quot;/users&quot;)public class UserController &#123;        @Autowired    private UserService userService;        @PostMapping    public ResponseEntity&lt;User&gt; createUser(@Valid @RequestBody UserCreateDTO dto) &#123;        User user = userService.create(dto);        return ResponseEntity.status(HttpStatus.CREATED).body(user);    &#125;        @GetMapping(&quot;/&#123;id&#125;&quot;)    public ResponseEntity&lt;User&gt; getUser(@PathVariable @Min(1) Long id) &#123;        User user = userService.findById(id);        return ResponseEntity.ok(user);    &#125;&#125;

3. 自定义校验注。// 自定义校验注。@Documented@Constraint(validatedBy = PhoneValidator.class)@Target(&#123;ElementType.FIELD, ElementType.PARAMETER&#125;)@Retention(RetentionPolicy.RUNTIME)public @interface Phone &#123;        String message() default &quot;手机号格式错。;        Class&lt;&gt;[] groups() default &#123;&#125;;        Class&lt; extends Payload&gt;[] payload() default &#123;&#125;;&#125;// 校验器实现public class PhoneValidator implements ConstraintValidator&lt;Phone, String&gt; &#123;        private static final Pattern PHONE_PATTERN = Pattern.compile(&quot;^1[3-9]\\d&#123;9&#125;$&quot;);        @Override    public void initialize(Phone constraintAnnotation) &#123;    &#125;        @Override    public boolean isValid(String value, ConstraintValidatorContext context) &#123;        if (value == null || value.isEmpty()) &#123;            return true;  // 空值由@NotBlank处理        &#125;        return PHONE_PATTERN.matcher(value).matches();    &#125;&#125;// 使用@Datapublic class UserDTO &#123;    @Phone(message = &quot;手机号格式错。)    private String phone;&#125;

4. 全局校验配置@Configurationpublic class ValidationConfig &#123;        /**     * 配置全局校验消息     */    @Bean    public Validator validator() &#123;        ValidatorFactory factory = Validation.byProvider(HibernateValidator.class)                .configure()                .addProperty(&quot;hibernate.validator.fail_fast&quot;, &quot;false&quot;)  // 校验所有字。                .buildValidatorFactory();        return factory.getValidator();    &#125;&#125;


三、接口请求日志统一打印1. 需求分析需要记录：

请求信息：URL、HTTP方法、请求头、请求参。- 响应信息：响应状态码、响应体
性能指标：请求耗时

2. 实现方式方式1：使用拦截器@Slf4j@Componentpublic class RequestLogInterceptor implements HandlerInterceptor &#123;        private static final String START_TIME = &quot;startTime&quot;;        @Override    public boolean preHandle(HttpServletRequest request,                             HttpServletResponse response,                             Object handler) throws Exception &#123;        // 记录开始时序        request.setAttribute(START_TIME, System.currentTimeMillis());                // 记录请求信息        log.info(&quot;========== 请求开发==========&quot;);        log.info(&quot;请求方法: &#123;&#125;&quot;, request.getMethod());        log.info(&quot;请求URL: &#123;&#125;&quot;, request.getRequestURI());        log.info(&quot;请求参数: &#123;&#125;&quot;, getRequestParams(request));                return true;    &#125;        @Override    public void afterCompletion(HttpServletRequest request,                                HttpServletResponse response,                                Object handler,                                Exception ex) throws Exception &#123;        // 计算耗时        long startTime = (long) request.getAttribute(START_TIME);        long duration = System.currentTimeMillis() - startTime;                // 记录响应信息        log.info(&quot;响应状态码: &#123;&#125;&quot;, response.getStatus());        log.info(&quot;请求耗时: &#123;&#125;ms&quot;, duration);        log.info(&quot;========== 请求结束 ==========\n&quot;);    &#125;        /**     * 获取请求参数     */    private String getRequestParams(HttpServletRequest request) &#123;        StringBuilder params = new StringBuilder();                // URL参数        Map&lt;String, String[]&gt; parameterMap = request.getParameterMap();        if (!parameterMap.isEmpty()) &#123;            params.append(&quot;URL参数: &quot;).append(parameterMap);        &#125;                // POST请求体（需要包装request        if (&quot;POST&quot;.equalsIgnoreCase(request.getMethod()) &amp;&amp;             request.getContentType() != null &amp;&amp;             request.getContentType().contains(&quot;application/json&quot;)) &#123;            try &#123;                String body = request.getReader().lines().collect(Collectors.joining());                params.append(&quot;, 请求。 &quot;).append(body);            &#125; catch (IOException e) &#123;                log.warn(&quot;读取请求体失。, e);            &#125;        &#125;                return params.toString();    &#125;&#125;// 配置@Configurationpublic class WebMvcConfig implements WebMvcConfigurer &#123;        @Autowired    private RequestLogInterceptor requestLogInterceptor;        @Override    public void addInterceptors(InterceptorRegistry registry) &#123;        registry.addInterceptor(requestLogInterceptor)                .addPathPatterns(&quot;/api/**&quot;)                .excludePathPatterns(&quot;/api/health&quot;);    &#125;&#125;

方式2：使用过滤器（支持读取请求体多次。// 请求体包装器public class RequestBodyWrapper extends HttpServletRequestWrapper &#123;        private final byte[] body;        public RequestBodyWrapper(HttpServletRequest request) throws IOException &#123;        super(request);        body = request.getInputStream().readAllBytes();    &#125;        @Override    public ServletInputStream getInputStream() throws IOException &#123;        return new ByteArrayInputStream(body);    &#125;        public String getBody() &#123;        return new String(body, StandardCharsets.UTF_8);    &#125;&#125;// 日志过滤。@Slf4j@Componentpublic class RequestLogFilter implements Filter &#123;        @Override    public void doFilter(ServletRequest request, ServletResponse response,                          FilterChain chain) throws IOException, ServletException &#123;        long startTime = System.currentTimeMillis();                // 包装request以支持多次读。        RequestBodyWrapper wrappedRequest = new RequestBodyWrapper((HttpServletRequest) request);                // 记录请求信息        log.info(&quot;请求: &#123;&#125; &#123;&#125;&quot;, wrappedRequest.getMethod(), wrappedRequest.getRequestURI());        log.info(&quot;参数: &#123;&#125;&quot;, wrappedRequest.getBody());                // 继续执行        chain.doFilter(wrappedRequest, response);                // 记录响应信息        long duration = System.currentTimeMillis() - startTime;        log.info(&quot;响应耗时: &#123;&#125;ms&quot;, duration);    &#125;&#125;

方式3：使用AOP（更灵活。@Slf4j@Aspect@Componentpublic class RequestLogAspect &#123;        @Around(&quot;execution(* com.example.controller..*.*(..))&quot;)    public Object logRequest(ProceedingJoinPoint joinPoint) throws Throwable &#123;        long startTime = System.currentTimeMillis();                // 获取请求信息        HttpServletRequest request = getRequest();        String method = request.getMethod();        String url = request.getRequestURI();                // 获取方法参数        Signature signature = joinPoint.getSignature();        String methodName = signature.getName();        Object[] args = joinPoint.getArgs();                log.info(&quot;请求开发 &#123;&#125; &#123;&#125; [&#123;&#125;]&quot;, method, url, methodName);        log.info(&quot;请求参数: &#123;&#125;&quot;, Arrays.toString(args));                // 执行方法        Object result = null;        try &#123;            result = joinPoint.proceed();            return result;        &#125; finally &#123;            long duration = System.currentTimeMillis() - startTime;            log.info(&quot;请求结束: &#123;&#125; &#123;&#125; [&#123;&#125;] 耗时: &#123;&#125;ms&quot;, method, url, methodName, duration);            log.info(&quot;响应结果: &#123;&#125;&quot;, result != null result.toString() : &quot;null&quot;);        &#125;    &#125;        private HttpServletRequest getRequest() &#123;        ServletRequestAttributes attributes =                 (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();        return attributes != null attributes.getRequest() : null;    &#125;&#125;

3. 日志输出示例========== 请求开发==========请求方法: POST请求URL: /api/users请求参数: URL参数: &#123;&#125;, 请求。 &#123;&quot;name&quot;:&quot;张三&quot;,&quot;email&quot;:&quot;test@example.com&quot;&#125;========== 请求结束 ==========响应状态码: 201请求耗时: 156ms


四、最佳实践总结


场景
最佳实现



全局异常处理
使用@RestControllerAdvice统一处理，区分业务异常和系统异常


参数校验
使用@Valid + 校验注解，DTO中定义校验规划


请求日志
使用Interceptor或AOP，注意不要打印敏感信息


日志级别
业务异常用warn，系统异常用error，请求日志用info


敏感信息
日志中脱敏处理（密码、手机号等）



总结这三个场景题都是生产环境必备的技能：

全局异常处理：提升用户体验，保护系统安全
参数校验：避免脏数据进入系统
请求日志：便于问题排查和性能监控

掌握这些知识，不仅能应对面试，还能写出更健壮的代码。

前言SpringBoot是Java后端开发的标配，面试时关于SpringBoot的问题几乎必问题022年我面试时被问到”自动配置原理”，当时只知道是@SpringBootApplication，但说不出底层原理。后来专门去看了SpringBoot的源码，才明白原来涉及到SPI机制和条件注解决一、SpringBoot 核心优势1. 核心优势总结
优势 说明
自动配置 基于条件注解自动装配Bean，无需大量XML配置
简化依。 Starter起步依赖，一站式引入所需依赖
嵌入式容。 内嵌Tomcat&#x2F;Jetty&#x2F;Undertow，一键启动
监控指标 Actuator提供健康检查、度量指。
配置管理 支持多环境配置、配置加。
生态完。 与Spring Cloud无缝集成，适合微服务
2. Starter起步依赖&lt;!-- 一个Starter包含所有相关依。--&gt;&lt;dependency&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-starter-web&lt;/artifactId&gt;&lt;/dependency&gt;&lt;!-- 等价于引入多个依。--&gt;&lt;dependency&gt; &lt;groupId&gt;org.springframework&lt;/groupId&gt; &lt;artifactId&gt;spring-web&lt;/artifactId&gt;&lt;/dependency&gt;&lt;dependency&gt; &lt;groupId&gt;org.springframework&lt;/groupId&gt; &lt;artifactId&gt;spring-webmvc&lt;/artifactId&gt;&lt;/dependency&gt;&lt;dependency&gt; &lt;groupId&gt;org.apache.tomcat.embed&lt;/groupId&gt; &lt;artifactId&gt;tomcat-embed-core&lt;/artifactId&gt;&lt;/dependency&gt;
3. 嵌入式容。// SpringApplication.run()启动时自动启动嵌入式Tomcat@SpringBootApplicationpublic class Application &#123; public static void main(String[] args) &#123; SpringApplication.run(Application.class, args); &#125;&#125;
二、SpringBoot 自动配置原理1. @SpringBootApplication 注解@SpringBootApplication // 等价于以下三个注解的组合public class Application &#123; &#125;
*等价。 @SpringBootConfiguration // 配置类，等价于@Configuration@EnableAutoConfiguration // 开启自动配置（核心。@ComponentScan(basePackages = &quot;com.example&quot;) // 扫描组件
2. @EnableAutoConfiguration 原理@EnableAutoConfiguration @Import(AutoConfigurationImportSelector.class) AutoConfigurationImportSelector.selectImports() →读取META-INF/spring.factories →加载所有EnableAutoConfiguration的实现类
3. spring.factories 文件# 自动配置类队列org.springframework.boot.autoconfigure.EnableAutoConfiguration=\org.springframework.boot.autoconfigure.web.servlet.WebMvcAutoConfiguration,\org.springframework.boot.autoconfigure.jdbc.DataSourceAutoConfiguration,\org.springframework.boot.autoconfigure.orm.jpa.HibernateJpaAutoConfiguration
4. 条件注解自动配置不是无条件的，需要满足特定条件：
条件注解 说明
@ConditionalOnClass 类路径上存在指定。
@ConditionalOnMissingClass 类路径上不存在指定类
@ConditionalOnBean 容器中存在指定Bean
@ConditionalOnMissingBean 容器中不存在指定Bean
@ConditionalOnProperty 配置属性满足条。
@ConditionalOnWebApplication 是Web应用
5. 自动配置示例// DataSourceAutoConfiguration 核心逻辑@Configuration@ConditionalOnClass(&#123; DataSource.class, EmbeddedDatabaseType.class &#125;)@ConditionalOnMissingBean(type = &quot;javax.sql.DataSource&quot;)@EnableConfigurationProperties(DataSourceProperties.class)public class DataSourceAutoConfiguration &#123; @Bean @ConditionalOnMissingBean public DataSource dataSource(DataSourceProperties properties) &#123; return properties.initializeDataSourceBuilder().build(); &#125;&#125;
工作流程 1. 检查类路径是否有DataSource和EmbeddedDatabaseType2. 检查容器中是否没有DataSource Bean3. 如果都满足，创建DataSource Bean 6. 自定义自动配置// 自定义Starter的自动配置@Configuration@ConditionalOnClass(MyService.class)@EnableConfigurationProperties(MyProperties.class)public class MyAutoConfiguration &#123; @Bean @ConditionalOnMissingBean public MyService myService(MyProperties properties) &#123; return new MyService(properties.getConfig()); &#125;&#125;
三、SpringMVC 执行流程1. 完整执行流程1. 用户发起HTTP请求 和 2. DispatcherServlet（前端控制器）接收请。 ?3. HandlerMapping（处理器映射）查找Controller 和 4. 返回HandlerExecutionChain（包含Handler和Interceptor? 5. HandlerAdapter（处理器适配器）调用Controller方法 和 6. Controller执行业务逻辑，返回ModelAndView 和 7. ViewResolver（视图解析器）解析视。 8. 渲染视图，返回HTTP响应
2. 核心组件
组件 职责
DispatcherServlet 前端控制器，请求入口
HandlerMapping 根据URL查找Controller
HandlerAdapter 适配调用Controller方法
HandlerInterceptor 请求拦截。
ViewResolver 视图解析。
3. 代码示例// Controller@RestController@RequestMapping(&quot;/users&quot;)public class UserController &#123; @Autowired private UserService userService; @GetMapping(&quot;/&#123;id&#125;&quot;) public ResponseEntity&lt;User&gt; getUser(@PathVariable Long id) &#123; User user = userService.findById(id); return ResponseEntity.ok(user); &#125;&#125;// HandlerMapping查找流程// 1. 请求URL: /users/1// 2. 匹配@RequestMapping(&quot;/users/&#123;id&#125;&quot;)// 3. 找到UserController.getUser()方法
4. HandlerInterceptor 执行时机public class MyInterceptor implements HandlerInterceptor &#123; // 请求到达Controller之前 @Override public boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception &#123; // 日志记录、权限校。 return true; // true继续执行，false中断 &#125; // Controller执行完成之后，视图渲染之。 @Override public void postHandle(HttpServletRequest request, HttpServletResponse response, Object handler, ModelAndView modelAndView) throws Exception &#123; // 修改ModelAndView &#125; // 整个请求完成之后 @Override public void afterCompletion(HttpServletRequest request, HttpServletResponse response, Object handler, Exception ex) throws Exception &#123; // 资源清理、日志记。 &#125;&#125;
5. 配置拦截。@Configurationpublic class WebMvcConfig implements WebMvcConfigurer &#123; @Override public void addInterceptors(InterceptorRegistry registry) &#123; registry.addInterceptor(new MyInterceptor()) .addPathPatterns(&quot;/**&quot;) // 拦截所有路径 .excludePathPatterns(&quot;/login&quot;); // 排除登录接口 &#125;&#125;
四、@Controller、@RestController、@ResponseBody 的区别1. 对比。
注解 说明 返回值处理
@Controller 传统MVC控制。 返回视图名或ModelAndView
@RestController RESTful控制。 返回JSON&#x2F;XML（自动@ResponseBody
@ResponseBody 方法级注。 将返回值转为JSON&#x2F;XML
2. 代码示例// @Controller：返回视。@Controllerpublic class ViewController &#123; @GetMapping(&quot;/index&quot;) public String index(Model model) &#123; model.addAttribute(&quot;name&quot;, &quot;张三&quot;); return &quot;index&quot;; // 返回视图名，由ViewResolver解析 &#125;&#125;// @RestController：返回JSON@RestControllerpublic class ApiController &#123; @GetMapping(&quot;/api/user&quot;) public User getUser() &#123; return new User(&quot;1&quot;, &quot;张三&quot;); // 自动转为JSON &#125;&#125;// @Controller + @ResponseBody：等价于@RestController@Controllerpublic class ApiController2 &#123; @GetMapping(&quot;/api/user&quot;) @ResponseBody public User getUser() &#123; return new User(&quot;1&quot;, &quot;张三&quot;); // 转为JSON &#125;&#125;
3. 底层原理// @RestController 源码@Target(ElementType.TYPE)@Retention(RetentionPolicy.RUNTIME)@Documented@Controller@ResponseBodypublic @interface RestController &#123; &#125;
结论：@RestController &#x3D; @Controller + @ResponseBody
五、全局异常处理。1. 为什么需要全局异常处理
问题 说明
用户体验。 直接返回堆栈信息，用户看不懂
安全风险 暴露系统内部结构和代码细。
格式不统一 不同异常返回不同格式，前端难处理
2. 实现方式@RestControllerAdvicepublic class GlobalExceptionHandler &#123; // 处理参数校验异常 @ExceptionHandler(MethodArgumentNotValidException.class) public ResponseEntity&lt;ErrorResponse&gt; handleValidationException( MethodArgumentNotValidException ex) &#123; String message = ex.getBindingResult() .getFieldErrors() .stream() .map(FieldError::getDefaultMessage) .collect(Collectors.joining(&quot;, &quot;)); return ResponseEntity.badRequest() .body(new ErrorResponse(400, &quot;参数校验失败&quot;, message)); &#125; // 处理业务异常 @ExceptionHandler(BusinessException.class) public ResponseEntity&lt;ErrorResponse&gt; handleBusinessException( BusinessException ex) &#123; return ResponseEntity.status(ex.getCode()) .body(new ErrorResponse(ex.getCode(), ex.getMessage(), null)); &#125; // 处理其他未知异常 @ExceptionHandler(Exception.class) public ResponseEntity&lt;ErrorResponse&gt; handleException(Exception ex) &#123; // 记录日志 log.error(&quot;系统异常&quot;, ex); // 返回通用错误信息，隐藏细。 return ResponseEntity.status(500) .body(new ErrorResponse(500, &quot;系统内部错误&quot;, null)); &#125;&#125;// 统一错误响应@Datapublic class ErrorResponse &#123; private Integer code; private String message; private String detail;&#125;
3. 自定义业务异。public class BusinessException extends RuntimeException &#123; private Integer code; public BusinessException(Integer code, String message) &#123; super(message); this.code = code; &#125; public BusinessException(String message) &#123; super(message); this.code = 400; &#125; // getter/setter&#125;// 使用throw new BusinessException(404, &quot;用户不存。);throw new BusinessException(&quot;参数不能为空&quot;);
总结SpringBoot的核心在于自动配置，理解SPI机制和条件注解是关键。SpringMVC的执行流程要记住DispatcherServlet这个入口，以及各个组件的职责。全局异常处理是生产环境必备的，能提升用户体验和系统安全指南这些知识不仅面试有用，日常开发中遇到问题时也能快速定位和解决策

前言SpringCloud Alibaba是微服务架构的核心技术栈，面试时必问。但如果你只背面试题，面试官追问项目经验就会露馅。2022-2024年我在智慧矿山项目中负责微服务架构设计与优化，经历过服务雪崩、配置混乱、调用超时等问题。这篇文章不仅讲解核心面试题，更结合实际项目经验，告诉你*在项目中怎么用的、踩过什么坑、怎么解决策 项目背景智慧矿山项目微服务架构┌─────────────────────────────────────────────────────────────────。 项目规模 ?? - 服务数量。0. - 日均请求。00万次 ?? - 服务注册/配置：Nacos集群 ?? - 服务限流：Sentinel →├─────────────────────────────────────────────────────────────────。 核心挑战 ?? - 服务雪崩：高并发下服务不可用 ?? - 配置管理：多环境配置、动态配置更。 ? - 调用超时：跨服务调用延迟。 - 服务治理：限流、熔断、降。 →└─────────────────────────────────────────────────────────────────。```---## 一、Nacos服务注册与配置（项目实战。### 1. Nacos核心概念（面试必备） Nacos架构┌─────────────────────────────────────────────────────────────────。 Nacos Server ?? ┌─────────────────────────────────────────────────────────。 ?? 服务注册中心 配置中心 集群管理 ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 Nacos Client ?? ┌─────────────────────────────────────────────────────────。 ? 服务注册 服务发现 配置订阅 配置更新 └─────────────────────────────────────────────────────────。 →└─────────────────────────────────────────────────────────────────。&#96;&#96;&#96; 2. 服务注册与发现（智慧矿山项目实战。# application.ymlspring: application: name: vehicle-service cloud: nacos: discovery: server-addr: nacos:8848 namespace: prod group: vehicle-group metadata: version: 1.0 weight: 100
// →原始配置（服务发现有问题。spring: cloud: nacos: discovery: server-addr: nacos:8848 # 问题：没有配置namespace，生产环境和测试环境的服务会混淆// →优化后的配置（解决环境隔离问题）spring: cloud: nacos: discovery: server-addr: nacos1:8848,nacos2:8848,nacos3:8848 # Nacos集群 namespace: $&#123;NACOS_NAMESPACE:prod&#125; # 环境隔离 group: $&#123;SERVICE_GROUP:vehicle-group&#125; # 服务分组 weight: $&#123;SERVICE_WEIGHT:100&#125; # 权重配置 enabled: true # 开启服务注。 register-enabled: true # 开启注。 heart-beat-interval: 5000 # 心跳间隔5. heart-beat-timeout: 15000 # 心跳超时15. ip-delete-timeout: 30000 # IP删除超时30.```### 3. Nacos配置中心（智慧矿山项目实战）```java// →原始配置（配置无法动态更新）@Configuration@ConfigurationProperties(prefix = &quot;vehicle&quot;)public class VehicleConfig &#123; private int maxSpeed = 40; private int minSpeed = 0; // 问题：修改配置后需要重启服务&#125;// →优化后的配置（支持动态更新）@Data@Configuration@ConfigurationProperties(prefix = &quot;vehicle&quot;)@RefreshScope // 支持动态刷新配置public class VehicleConfig &#123; private int maxSpeed = 40; private int minSpeed = 0; private int alertDistance = 5; @Value(&quot;$&#123;vehicle.emergency-brake-enabled:true&#125;&quot;) private boolean emergencyBrakeEnabled;&#125;// 配置监听@Componentpublic class NacosConfigListener &#123; @NacosConfigListener(dataId = &quot;vehicle-service.yaml&quot;, groupId = &quot;DEFAULT_GROUP&quot;) public void onConfigChanged(String config) &#123; log.info(&quot;配置变更: &#123;&#125;&quot;, config); // 重新加载配置 &#125;&#125;
4. Nacos踩坑记录Nacos踩坑1：服务注册延。→问题：服务启动后，其他服务无法立即发布解决：配置健康检查延迟、心跳间。Nacos踩坑2：配置中心连接失。→问题：Nacos服务器宕机后，应用启动失。→解决：配置本地缓存、启动重试机制Nacos踩坑3：命名空间隔离问题：测试环境和生产环境服务混淆→解决：按namespace隔离、按group分组
二、Sentinel限流熔断（项目实战重点）1. Sentinel核心概念（面试必备）Sentinel架构┌─────────────────────────────────────────────────────────────────。 Sentinel Dashboard ?? ┌─────────────────────────────────────────────────────────。 ?? 规则配置 实时监控 簇点链路 ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 Sentinel Client ?? ┌─────────────────────────────────────────────────────────。 ? 限流规则 熔断规则 降级规则 系统规则 └─────────────────────────────────────────────────────────。 →└─────────────────────────────────────────────────────────────────。```### 2. 服务雪崩问题（智慧矿山项目实战）**项目背景** - 订单服务依赖库存服务- 库存服务宕机- 订单服务也跟着宕机**项目数据** - 服务雪崩频率。- 系统恢复时间。0分钟- 解决方案：Sentinel限流熔断```java// →原始代码（存在服务雪崩问题）@Servicepublic class OrderService &#123; @Autowired private InventoryFeignClient inventoryClient; public Order createOrder(String productId) &#123; // 问题：库存服务宕机时，订单服务也跟着宕机 Inventory inventory = inventoryClient.getInventory(productId); Order order = new Order(); order.setProductId(productId); order.setInventory(inventory); return order; &#125;&#125;// 问题分析。// 1. 库存服务响应用// 2. 订单服务等待时间。// 3. 线程池耗尽// 4. 订单服务也宕。// →优化后的代码（解决服务雪崩）- Sentinel限流@Configurationpublic class SentinelConfig &#123; @Bean public SentinelResourceAspect sentinelResourceAspect() &#123; return new SentinelResourceAspect(); &#125;&#125;@Servicepublic class OrderService &#123; @Autowired private InventoryFeignClient inventoryClient; public Order createOrder(String productId) &#123; try &#123; // 使用Sentinel保护资源 return SentinelExecutor.execute(() -&gt; &#123; Inventory inventory = inventoryClient.getInventory(productId); Order order = new Order(); order.setProductId(productId); order.setInventory(inventory); return order; &#125;, &quot;order-service&quot;, &quot;default&quot;); &#125; catch (BlockException e) &#123; // 限流时返回降级结构 log.warn(&quot;订单服务限流，返回降级结构); return getFallbackOrder(productId); &#125; &#125; private Order getFallbackOrder(String productId) &#123; Order order = new Order(); order.setProductId(productId); order.setInventory(null); order.setRemark(&quot;系统繁忙，请稍后重试&quot;); return order; &#125;&#125;// →优化后的代码（解决服务雪崩）- Sentinel熔断@SentinelResource( value = &quot;getInventory&quot;, blockHandler = &quot;getInventoryBlockHandler&quot;, fallback = &quot;getInventoryFallback&quot;)public Inventory getInventory(String productId) &#123; return inventoryClient.getInventory(productId);&#125;// 限流处理public Inventory getInventoryBlockHandler(String productId, BlockException e) &#123; log.warn(&quot;库存服务限流, productId=&#123;&#125;&quot;, productId); return new Inventory(productId, 0, &quot;系统繁忙&quot;);&#125;// 降级处理public Inventory getInventoryFallback(String productId, Throwable e) &#123; log.warn(&quot;库存服务降级, productId=&#123;&#125;, error=&#123;&#125;&quot;, productId, e.getMessage()); return new Inventory(productId, 0, &quot;服务不可靠);&#125;
3. Sentinel熔断策略// Sentinel熔断配置@Configurationpublic class SentinelRuleConfig &#123; @PostConstruct public void initSentinelRules() &#123; List&lt;DegradeRule&gt; rules = new ArrayList&lt;&gt;(); DegradeRule rule = new DegradeRule(&quot;inventory-feign&quot;) .setGrade(CircuitBreakerStrategy.ERROR_COUNT.getType()) .setCount(5) // 5次错误触发熔。 .setSlowRatioThreshold(0.5) // 50%慢调用比例触发熔。 .setMinRequestAmount(5) // 最小请求数 .setStatIntervalMs(10000) // 10秒内 .setTimeWindow(10); // 熔断时长10. rules.add(rule); DegradeRuleManager.loadRules(rules); &#125;&#125;// 熔断策略对比| 策略 | 说明 | 适用场景 ||------|------|----------|| 慢调用比。| 响应时间超过阈值比例触发熔。| 下游服务响应用|| 异常比例 | 异常比例超过阈值触发熔。| 下游服务不稳。|| 异常。| 异常数量超过阈值触发熔。| 下游服务偶尔失败 |
4. Sentinel限流策略// Sentinel限流配置@Configurationpublic class SentinelFlowConfig &#123; @PostConstruct public void initFlowRules() &#123; List&lt;FlowRule&gt; rules = new ArrayList&lt;&gt;(); // 订单创建接口限流 FlowRule orderRule = new FlowRule(&quot;createOrder&quot;) .setGrade(RuleConstant.FLOW_GRADE_QPS) .setCount(1000) // 1000 QPS .setControlBehavior(RuleConstant.CONTROL_BEHAVIOR_DEFAULT) .setStrategy(RuleConstant.STRATEGY_DIRECT); rules.add(orderRule); FlowRuleManager.loadRules(rules); &#125;&#125;// 限流效果对比| 效果 | 说明 | 适用场景 ||------|------|----------|| 直接拒绝 | 请求超过阈值直接拒。| 适合前端限流 || 冷启动| 逐渐增加QPS | 适合系统冷启动|| 匀速排。| 请求匀速通过 | 适合削峰填谷 |
三、Gateway网关（项目实战）1. Gateway核心概念（面试必备）Gateway架构┌─────────────────────────────────────────────────────────────────。 请求 →├─────────────────────────────────────────────────────────────────。 Route（路由） ?? ┌─────────────────────────────────────────────────────────。 ?? 路由规则 断言 过滤。 ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 过滤器链 ?? ┌─────────────────────────────────────────────────────────。 ?? 认证授权 限流熔断 日志监控 协议转换 ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 微服务 ?? ┌─────────────────────────────────────────────────────────。 ? 用户服务 订单服务 库存服务 支付服务 └─────────────────────────────────────────────────────────。 →└─────────────────────────────────────────────────────────────────。```### 2. Gateway路由配置（智慧矿山项目实战）```yaml# Gateway配置spring: cloud: gateway: discovery: locator: enabled: true # 开启服务发布 lower-case-service-id: true # 服务ID小写 routes: - id: vehicle-service uri: lb://vehicle-service # lb表示负载均衡 predicates: - Path=/vehicle/** - Method=GET,POST filters: - StripPrefix=1 # 去掉第一层路径 - RequestRateLimiter=10,20 # 限流10QPS - id: order-service uri: lb://order-service predicates: - Path=/order/** filters: - StripPrefix=1 - name: RequestSize args: maxSize: 10MB
3. Gateway过滤器（智慧矿山项目实战。// 全局认证过滤。@Componentpublic class AuthGlobalFilter implements GlobalFilter, Ordered &#123; @Autowired private JwtUtil jwtUtil; @Override public Mono&lt;Void&gt; filter(ServerWebExchange exchange, GatewayFilterChain chain) &#123; ServerHttpRequest request = exchange.getRequest(); // 1. 获取Token String token = request.getHeaders().getFirst(&quot;Authorization&quot;); // 2. 验证Token if (StringUtils.isBlank(token)) &#123; ServerHttpResponse response = exchange.getResponse(); response.setStatusCode(HttpStatus.UNAUTHORIZED); return response.setComplete(); &#125; try &#123; Claims claims = jwtUtil.parseToken(token); String userId = claims.getSubject(); // 3. 将用户ID添加到请求头 ServerHttpRequest modifiedRequest = request.mutate() .header(&quot;X-User-Id&quot;, userId) .build(); return chain.filter(exchange.mutate().request(modifiedRequest).build()); &#125; catch (Exception e) &#123; ServerHttpResponse response = exchange.getResponse(); response.setStatusCode(HttpStatus.UNAUTHORIZED); return response.setComplete(); &#125; &#125; @Override public int getOrder() &#123; return -100; // 优先级最。 &#125;&#125;// 限流过滤。@Componentpublic class RateLimitFilter implements GlobalFilter &#123; @Autowired private RedisRateLimiter rateLimiter; @Override public Mono&lt;Void&gt; filter(ServerWebExchange exchange, GatewayFilterChain chain) &#123; String key = exchange.getRequest().getPath().value(); return rateLimiter.isAllowed(key, &quot;100&quot;).flatMap(allowed -&gt; &#123; if (allowed) &#123; return chain.filter(exchange); &#125; ServerHttpResponse response = exchange.getResponse(); response.setStatusCode(HttpStatus.TOO_MANY_REQUESTS); return response.setComplete(); &#125;); &#125;&#125;
四、Feign远程调用（项目实战）1. Feign核心配置（智慧矿山项目实战）# Feign配置feign: client: config: default: connectTimeout: 5000 # 连接超时5. readTimeout: 10000 # 读取超时10. loggerLevel: basic # 日志级别 vehicle-service: connectTimeout: 3000 readTimeout: 5000 compression: request: enabled: true # 开启请求压。 response: enabled: true # 开启响应压。 httpclient: enabled: true # 使用Apache HttpClient maxConnections: 1000 # 最大连接数 maxConnectionsPerRoute: 100 # 每个路由最大连接数
2. Feign超时配置（智慧矿山项目实战）// →原始配置（超时配置不合理。@FeignClient(name = &quot;inventory-service&quot;)public interface InventoryFeignClient &#123; @GetMapping(&quot;/inventory/&#123;productId&#125;&quot;) Inventory getInventory(@PathVariable String productId);&#125;// 问题分析。// 1. 默认超时时间30秒，太长// 2. 库存服务实际响应时间1.// 3. 超时配置不合。// →优化后的配置（合理配置超时）@Configurationpublic class FeignConfig &#123; @Bean public Request.Options requestOptions() &#123; // 连接超时3秒，读取超时5. return new Request.Options(3000, 5000); &#125;&#125;@FeignClient( name = &quot;inventory-service&quot;, configuration = FeignConfig.class, fallback = InventoryFeignClientFallback.class # 降级处理)public interface InventoryFeignClient &#123; @GetMapping(&quot;/inventory/&#123;productId&#125;&quot;) Inventory getInventory(@PathVariable String productId);&#125;// Feign降级处理@Componentpublic class InventoryFeignClientFallback implements InventoryFeignClient &#123; @Override public Inventory getInventory(String productId) &#123; log.warn(&quot;库存服务降级返回, productId=&#123;&#125;&quot;, productId); return new Inventory(productId, 0, &quot;库存服务不可靠); &#125;&#125;
3. Feign重试配置（智慧矿山项目实战）// Feign重试配置@Configurationpublic class FeignRetryConfig &#123; @Bean public Retryer feignRetryer() &#123; // 重试3次，每次间隔100-500ms return new Retryer.Default(100, 500, 3); &#125;&#125;// 项目经验。// 1. 重试次数不宜过多（最次）// 2. 重试间隔要有随机性（避免惊群效应用// 3. 只对GET请求重试（POST请求重试可能导致数据重复。// 4. 幂等性接口才能重复```---## 五、项目总结### 1. 核心数据汇。| 指标 | 优化工| 优化工| 提升 ||------|--------|--------|------|| 服务雪崩频率 | 5. | 0. | 100% || 系统恢复时间 | 30分钟 | 5分钟 | 6.|| 接口限流能力 | 0 | 10000 QPS | 10000.|| 服务调用超时 | 30.| 5.| 6.|| 系统可用。| 99.5% | 99.9% | 4.9% |### 2. 核心经验总结
Nacos：服务注册与发现、配置中心、命名空间隔离2. Sentinel：限流、熔断、降级、解决服务雪。3. Gateway：路由、认证、日志、协议转账4. Feign：远程调用、超时配置、重试机制&#96;&#96;&#96;
3. 面试高频追问Q1：Nacos和Eureka的区别？ A：Nacos支持CP和AP模式，Eureka只支持AP
Q2：Sentinel和Hystrix的区别？ A：Sentinel功能更丰富，配置更简。 Q3：Gateway和Zuul的区别？ A：Gateway基于WebFlux，性能更高
Q4：Feign和Ribbon的区别？ A：Feign是声明式的，Ribbon需要手动调优```
