性能优化1. Redis缓存优化@Servicepublic class VehicleStateCache &#123; @Autowired private RedisTemplate&lt;String, Object&gt; redisTemplate; // 缓存车辆状态，5秒过期 public void updateVehicleState(Long vehicleId, VehicleState state) &#123; String key = &quot;vehicle:state:&quot; + vehicleId; redisTemplate.opsForValue().set(key, state, 5, TimeUnit.SECONDS); &#125; // 批量获取车辆状态 public Map&lt;Long, VehicleState&gt; batchGetVehicleState(List&lt;Long&gt; vehicleIds) &#123; List&lt;String&gt; keys = vehicleIds.stream() .map(id -&gt; &quot;vehicle:state:&quot; + id) .collect(Collectors.toList()); List&lt;Object&gt; values = redisTemplate.opsForValue().multiGet(keys); Map&lt;Long, VehicleState&gt; result = new HashMap&lt;&gt;(); for (int i = 0; i &lt; vehicleIds.size(); i++) &#123; if (values.get(i) != null) &#123; result.put(vehicleIds.get(i), (VehicleState) values.get(i)); &#125; &#125; return result; &#125;&#125;
