2. 子表自动创建// TDengine服务@Servicepublic class TDengineService &#123;        @Autowired    private JdbcTemplate jdbcTemplate;        /**     * 自动创建子表     */    public void createSubTable(String deviceId, String deviceType, String location) &#123;        String sql = String.format(            &quot;CREATE TABLE IF NOT EXISTS sensor_data_%s USING sensor_data TAGS (&#x27;%s&#x27;, &#x27;%s&#x27;, &#x27;%s&#x27;, &#x27;temperature&#x27;)&quot;,            deviceId, deviceId, deviceType, location        );                jdbcTemplate.execute(sql);    &#125;        /**     * 批量创建子表     */    public void batchCreateSubTables(List&lt;Device&gt; devices) &#123;        for (Device device : devices) &#123;            createSubTable(                device.getDeviceId(),                device.getDeviceType(),                device.getLocation()            );        &#125;    &#125;&#125;


三、数据写入优化1. 单条数据写入// 数据写入服务@Servicepublic class DataWriteService &#123;        @Autowired    private TDengineService tdengineService;        /**     * 写入传感器数据     */    public void writeSensorData(SensorData data) &#123;        String sql = String.format(            &quot;INSERT INTO sensor_data_%s VALUES (%d, %f, %d, %d)&quot;,            data.getDeviceId(),            data.getTimestamp(),            data.getValue(),            data.getQuality(),            data.getStatus()        );                tdengineService.execute(sql);    &#125;&#125;

2. 批量数据写入（性能优化工// 批量数据写入服务@Servicepublic class BatchDataWriteService &#123;        @Autowired    private TDengineService tdengineService;        private BlockingQueue&lt;SensorData&gt; dataQueue = new LinkedBlockingQueue&lt;&gt;(10000);        /**     * 批量写入数据     */    @Scheduled(fixedRate = 1000)    public void batchWrite() &#123;        List&lt;SensorData&gt; batch = new ArrayList&lt;&gt;();        dataQueue.drainTo(batch, 1000);                if (batch.isEmpty()) &#123;            return;        &#125;                // 构建批量插入SQL        StringBuilder sql = new StringBuilder(&quot;INSERT INTO &quot;);                for (SensorData data : batch) &#123;            sql.append(String.format(                &quot;sensor_data_%s VALUES (%d, %f, %d, %d) &quot;,                data.getDeviceId(),                data.getTimestamp(),                data.getValue(),                data.getQuality(),                data.getStatus()            ));        &#125;                tdengineService.execute(sql.toString());    &#125;        /**     * 添加数据到队。     */    public void addData(SensorData data) &#123;        dataQueue.offer(data);    &#125;&#125;

3. 高性能写入配置// TDengine配置@Configurationpublic class TDengineConfig &#123;        @Bean    public DataSource tdengineDataSource() &#123;        HikariDataSource dataSource = new HikariDataSource();        dataSource.setJdbcUrl(&quot;jdbc:TAOS://tdengine:6030/smart_mine&quot;);        dataSource.setUsername(&quot;root&quot;);        dataSource.setPassword(&quot;taosdata&quot;);        dataSource.setMaximumPoolSize(100);  // 连接池大。        dataSource.setMinimumIdle(10);        dataSource.setConnectionTimeout(30000);        dataSource.setIdleTimeout(600000);        dataSource.setMaxLifetime(1800000);                return dataSource;    &#125;&#125;


四、数据查询优化1. 时间范围查询// 数据查询服务@Servicepublic class DataQueryService &#123;        @Autowired    private TDengineService tdengineService;        /**     * 查询设备历史数据     */    public List&lt;SensorData&gt; queryHistory(String deviceId, long startTime, long endTime) &#123;        String sql = String.format(            &quot;SELECT * FROM sensor_data_%s WHERE ts &gt;= %d AND ts &lt;= %d&quot;,            deviceId, startTime, endTime        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                return results.stream()            .map(this::mapToSensorData)            .collect(Collectors.toList());    &#125;        /**     * 查询最近N条数据     */    public List&lt;SensorData&gt; queryRecent(String deviceId, int limit) &#123;        String sql = String.format(            &quot;SELECT * FROM sensor_data_%s ORDER BY ts DESC LIMIT %d&quot;,            deviceId, limit        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                return results.stream()            .map(this::mapToSensorData)            .collect(Collectors.toList());    &#125;&#125;

2. 聚合查询// 聚合查询服务@Servicepublic class AggregateQueryService &#123;        /**     * 查询平均。     */    public Double queryAverage(String deviceId, long startTime, long endTime) &#123;        String sql = String.format(            &quot;SELECT AVG(value) FROM sensor_data_%s WHERE ts &gt;= %d AND ts &lt;= %d&quot;,            deviceId, startTime, endTime        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                return (Double) results.get(0).get(&quot;AVG(value)&quot;);    &#125;        /**     * 查询最大最小。     */    public MaxMinResult queryMaxMin(String deviceId, long startTime, long endTime) &#123;        String sql = String.format(            &quot;SELECT MAX(value), MIN(value) FROM sensor_data_%s WHERE ts &gt;= %d AND ts &lt;= %d&quot;,            deviceId, startTime, endTime        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                return MaxMinResult.builder()            .maxValue((Double) results.get(0).get(&quot;MAX(value)&quot;))            .minValue((Double) results.get(0).get(&quot;MIN(value)&quot;))            .build();    &#125;        /**     * 查询统计数据     */    public StatisticsResult queryStatistics(String deviceId, long startTime, long endTime) &#123;        String sql = String.format(            &quot;SELECT COUNT(*), AVG(value), MAX(value), MIN(value), STDDEV(value) FROM sensor_data_%s WHERE ts &gt;= %d AND ts &lt;= %d&quot;,            deviceId, startTime, endTime        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                return StatisticsResult.builder()            .count((Long) results.get(0).get(&quot;COUNT(*)&quot;))            .average((Double) results.get(0).get(&quot;AVG(value)&quot;))            .max((Double) results.get(0).get(&quot;MAX(value)&quot;))            .min((Double) results.get(0).get(&quot;MIN(value)&quot;))            .stddev((Double) results.get(0).get(&quot;STDDEV(value)&quot;))            .build();    &#125;&#125;

3. 时间窗口查询// 时间窗口查询服务@Servicepublic class TimeWindowQueryService &#123;        /**     * 按小时聚合查询     */    public List&lt;HourlyAggregate&gt; queryHourlyAggregate(String deviceId, long startTime, long endTime) &#123;        String sql = String.format(            &quot;SELECT _wstart, AVG(value), MAX(value), MIN(value) FROM sensor_data_%s &quot; +            &quot;WHERE ts &gt;= %d AND ts &lt;= %d INTERVAL(1h)&quot;,            deviceId, startTime, endTime        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                return results.stream()            .map(r -&gt; HourlyAggregate.builder()                .timestamp((Long) r.get(&quot;_wstart&quot;))                .average((Double) r.get(&quot;AVG(value)&quot;))                .max((Double) r.get(&quot;MAX(value)&quot;))                .min((Double) r.get(&quot;MIN(value)&quot;))                .build())            .collect(Collectors.toList());    &#125;        /**     * 按天聚合查询     */    public List&lt;DailyAggregate&gt; queryDailyAggregate(String deviceId, long startTime, long endTime) &#123;        String sql = String.format(            &quot;SELECT _wstart, AVG(value), MAX(value), MIN(value), COUNT(*) FROM sensor_data_%s &quot; +            &quot;WHERE ts &gt;= %d AND ts &lt;= %d INTERVAL(1d)&quot;,            deviceId, startTime, endTime        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                return results.stream()            .map(r -&gt; DailyAggregate.builder()                .timestamp((Long) r.get(&quot;_wstart&quot;))                .average((Double) r.get(&quot;AVG(value)&quot;))                .max((Double) r.get(&quot;MAX(value)&quot;))                .min((Double) r.get(&quot;MIN(value)&quot;))                .count((Long) r.get(&quot;COUNT(*)&quot;))                .build())            .collect(Collectors.toList());    &#125;&#125;


五、数据降采样与压。1. 数据降采。// 数据降采样服务@Servicepublic class DataDownsamplingService &#123;        /**     * 降采样存。     */    public void downsampleData(String deviceId) &#123;        // 1. 查询原始数据        long endTime = System.currentTimeMillis();        long startTime = endTime - 24 * 60 * 60 * 1000;  // 最。4小时                String sql = String.format(            &quot;SELECT _wstart, AVG(value), MAX(value), MIN(value) FROM sensor_data_%s &quot; +            &quot;WHERE ts &gt;= %d AND ts &lt;= %d INTERVAL(1h)&quot;,            deviceId, startTime, endTime        );                List&lt;Map&lt;String, Object&gt;&gt; results = tdengineService.query(sql);                // 2. 存储降采样数据        for (Map&lt;String, Object&gt; result : results) &#123;            String insertSql = String.format(                &quot;INSERT INTO sensor_data_hourly_%s VALUES (%d, %f, %f, %f)&quot;,                deviceId,                result.get(&quot;_wstart&quot;),                result.get(&quot;AVG(value)&quot;),                result.get(&quot;MAX(value)&quot;),                result.get(&quot;MIN(value)&quot;)            );                        tdengineService.execute(insertSql);        &#125;                // 3. 删除原始数据        String deleteSql = String.format(            &quot;DELETE FROM sensor_data_%s WHERE ts &gt;= %d AND ts &lt;= %d&quot;,            deviceId, startTime, endTime        );                tdengineService.execute(deleteSql);    &#125;&#125;

2. 数据压缩配置-- TDengine压缩配置-- 自动压缩，无需手动配置-- 压缩率可靠0%-- 查看压缩效果SELECT COUNT(*) FROM sensor_data;-- 查看存储空间SHOW VGROUPS;


六、性能优化实战1. 写入性能优化// 写入性能优化@Servicepublic class WritePerformanceOptimization &#123;        /**     * 批量写入优化     */    public void optimizeBatchWrite(List&lt;SensorData&gt; dataList) &#123;        // 1. 按设备分析        Map&lt;String, List&lt;SensorData&gt;&gt; groupedData = dataList.stream()            .collect(Collectors.groupingBy(SensorData::getDeviceId));                // 2. 构建批量插入SQL        StringBuilder sql = new StringBuilder(&quot;INSERT INTO &quot;);                for (Map.Entry&lt;String, List&lt;SensorData&gt;&gt; entry : groupedData.entrySet()) &#123;            String deviceId = entry.getKey();            List&lt;SensorData&gt; data = entry.getValue();                        for (SensorData d : data) &#123;                sql.append(String.format(                    &quot;sensor_data_%s VALUES (%d, %f, %d, %d) &quot;,                    deviceId, d.getTimestamp(), d.getValue(), d.getQuality(), d.getStatus()                ));            &#125;        &#125;                // 3. 执行批量插入        tdengineService.execute(sql.toString());    &#125;&#125;

2. 查询性能优化// 查询性能优化@Servicepublic class QueryPerformanceOptimization &#123;        /**     * 查询缓存     */    @Autowired    private RedisTemplate&lt;String, String&gt; redisTemplate;        /**     * 缓存查询结果     */    public List&lt;SensorData&gt; queryWithCache(String deviceId, long startTime, long endTime) &#123;        String cacheKey = &quot;query:&quot; + deviceId + &quot;:&quot; + startTime + &quot;:&quot; + endTime;                // 1. 查询缓存        String cachedResult = redisTemplate.opsForValue().get(cacheKey);                if (cachedResult != null) &#123;            return JSON.parseArray(cachedResult, SensorData.class);        &#125;                // 2. 查询TDengine        List&lt;SensorData&gt; result = queryHistory(deviceId, startTime, endTime);                // 3. 缓存结果        redisTemplate.opsForValue().set(            cacheKey,            JSON.toJSONString(result),            5, TimeUnit.MINUTES        );                return result;    &#125;&#125;


七、项目踩坑记。1. 子表创建问题问题描述 - 每次写入数据前都需要判断子表是否存。- 大量设备导致子表创建耗时过长
解决方案 &#96;&#96;&#96;java&#x2F;&#x2F; 1. 批量预创建子。public void batchCreateSubTables(List devices) {    StringBuilder sql &#x3D; new StringBuilder();
for (Device device : devices) {
    sql.append(String.format(
        &quot;CREATE TABLE IF NOT EXISTS sensor_data_%s USING sensor_data TAGS (&#39;%s&#39;, &#39;%s&#39;, &#39;%s&#39;, &#39;temperature&#39;);&quot;,
        device.getDeviceId(), device.getDeviceId(), device.getDeviceType(), device.getLocation()
    ));
}

tdengineService.execute(sql.toString());

}
&#x2F;&#x2F; 2. 设备注册时自动创建子。public Device registerDevice(DeviceRegisterDTO dto) {    Device device &#x3D; deviceRepository.save(dto);
// 自动创建子表
createSubTable(device.getDeviceId(), device.getDeviceType(), device.getLocation());

return device;

}
### 2. 查询性能问题**问题描述** - 查询1个月历史数据耗时超过10.- 聚合查询性能下降**解决方案** ```java// 1. 使用时间窗口查询String sql = String.format(    &quot;SELECT _wstart, AVG(value) FROM sensor_data_%s &quot; +    &quot;WHERE ts &gt;= %d AND ts &lt;= %d INTERVAL(1h)&quot;,    deviceId, startTime, endTime);// 2. 使用降采样数据// 查询降采样后的数据，减少数据。// 3. 添加查询缓存// 使用Redis缓存查询结果

3. 数据存储问题问题描述 - 数据量过大，存储空间不足

历史数据查询性能下降

解决方案 &#96;&#96;&#96;java&#x2F;&#x2F; 1. 数据降采。&#x2F;&#x2F; 历史数据降采样存储，减少数据。&#x2F;&#x2F; 2. 数据冷热分离&#x2F;&#x2F; 最天数据存储到Redis，历史数据存储到TDengine
&#x2F;&#x2F; 3. 数据自动压缩&#x2F;&#x2F; TDengine自动压缩，压缩率90%

