## 总结

TDengine在智慧矿山项目中的核心价值是。*高性能写入、快速查询、自动压。*。关键技术点。
1. **超级表设备*：子表自动创建、标签设备2. **批量写入**：批量插入SQL、连接池优化
3. **查询优化**：时间窗口查询、聚合函数、查询缓存4. **数据降采。*：历史数据降采样、冷热分析
这是智慧矿山项目数据处理的核心技术，解决了MySQL无法支撑海量时序数据的问题

前言本文详细介绍智慧园区能耗监测系统的设计与实现，该系统覆盖50+园区、10000+设备，日均处理500万条数据。通过时序数据库和实时流处理技术，实现了能耗数据的采集、存储、分析和可视化 项目背景项目规模 覆盖范围：50+智慧园区 设备数量：10000+智能电表、水表、气表 日均数据量：500万条 查询响应：秒级响应 数据存储：3年历史数据
技术挑战 海量数据写入：10000+设备同时上报数据，写入吞吐量要求高 实时分析需求：需要实时统计各园区能耗数据 历史数据查询：支持3年历史数据的聚合查询 异常检测：需要实时检测能耗异常情况
技术架构整体架构设备。→采集。→存储。→计算法应用。```- **设备。*：智能电表、水表、气。- **采集。*：MQTT协议，EMQX集群- **存储。*：TDengine时序数据。- **计算法*：Flink实时流处理- **应用。*：SpringBoot + Vue### 技术选型| 组件 | 选型 | 理由 ||------|------|------|| 消息队列 | Kafka | 高吞吐量，支持重复|| 时序数据。| TDengine | 高写入性能，压缩率。|| 实时处理 | Flink | Exactly-once语义，事件时间处理|| 缓存 | Redis | 支持复杂数据类型，集群部。|## 核心模块设计### 1. 数据采集模块```java@Servicepublic class EnergyCollector &#123; @Autowired private KafkaTemplate&lt;String, EnergyData&gt; kafkaTemplate; /** * 采集能耗数据 * 设备每分钟上报一次数据 */ public void collect(EnergyData data) &#123; // 数据校验 if (!validate(data)) &#123; log.warn(&quot;数据校验失败: &#123;&#125;&quot;, data); return; &#125; // 发送到Kafka kafkaTemplate.send(&quot;energy-data&quot;, data.getDeviceId(), data); &#125; private boolean validate(EnergyData data) &#123; // 数据范围校验 if (data.getValue() &lt; 0 || data.getValue() &gt; 10000) &#123; return false; &#125; // 时间戳校。 if (Math.abs(System.currentTimeMillis() - data.getTimestamp()) &gt; 60000) &#123; return false; &#125; return true; &#125;&#125;
2. 实时计算模块public class EnergyAggregator extends KeyedProcessFunction&lt;String, EnergyData, AggregatedData&gt; &#123; // 状态存储每个设备的当前统计 ValueState&lt;EnergyStats&gt; statsState; @Override public void open(Configuration parameters) &#123; statsState = getRuntimeContext().getState( new ValueStateDescriptor&lt;&gt;(&quot;stats&quot;, EnergyStats.class) ); &#125; @Override public void processElement(EnergyData data, Context ctx, Collector&lt;AggregatedData&gt; out) throws Exception &#123; EnergyStats stats = statsState.value(); if (stats == null) &#123; stats = new EnergyStats(); stats.setDeviceId(data.getDeviceId()); stats.setStartTime(data.getTimestamp()); &#125; // 更新统计数据 stats.addValue(data.getValue()); stats.setCount(stats.getCount() + 1); stats.setSum(stats.getSum() + data.getValue()); stats.setMax(Math.max(stats.getMax(), data.getValue())); stats.setMin(Math.min(stats.getMin(), data.getValue())); stats.setLastUpdateTime(data.getTimestamp()); // 每分钟输出一次统。 if (data.getTimestamp() - stats.getStartTime() &gt;= 60000) &#123; out.collect(stats.toAggregatedData()); stats.reset(); &#125; statsState.update(stats); &#125;&#125;
3. 异常检测模式public class AnomalyDetector &#123; /** * 基于统计的异常检查 * 检测能耗是否超过历史平均的3倍标准差 */ public boolean isAnomaly(EnergyData data, EnergyStats historicalStats) &#123; double mean = historicalStats.getSum() / historicalStats.getCount(); double variance = historicalStats.getVariance(); double stdDev = Math.sqrt(variance); // 超过3倍标准差视为异常 return Math.abs(data.getValue() - mean) &gt; 3 * stdDev; &#125; /** * 环比异常检查 * 检测与上一个周期相比的异常波动 */ public boolean isSuddenChange(EnergyData current, EnergyData previous) &#123; if (previous.getValue() == 0) &#123; return current.getValue() &gt; 0; &#125; double changeRate = Math.abs(current.getValue() - previous.getValue()) / previous.getValue(); // 波动超过50%视为异常 return changeRate &gt; 0.5; &#125;&#125;
4. 能耗统计模式@Servicepublic class EnergyReportService &#123; @Autowired private TDengineService tdengineService; /** * 按园区统计日能耗 */ public List&lt;ParkEnergyStat&gt; getDailyParkEnergy(Long parkId, LocalDate date) &#123; String sql = String.format(&quot;&quot;&quot; SELECT LAST(water), LAST(electricity), LAST(gas), SUM(water) as total_water, SUM(electricity) as total_electricity, SUM(gas) as total_gas FROM energy_data WHERE park_id = %d AND ts &gt;= &#x27;%s&#x27; AND ts &lt; &#x27;%s&#x27; PARTITION BY park_id &quot;&quot;&quot;, parkId, date.atStartOfDay(), date.plusDays(1).atStartOfDay()); return tdengineService.query(sql, ParkEnergyStat.class); &#125; /** * 按设备统计月能耗趋。 */ public List&lt;DeviceEnergyTrend&gt; getDeviceTrend(Long deviceId, LocalDate startDate, LocalDate endDate) &#123; String sql = String.format(&quot;&quot;&quot; SELECT FIRST(value), LAST(value), AVG(value), SUM(value) FROM energy_data WHERE device_id = %d AND ts &gt;= &#x27;%s&#x27; AND ts &lt; &#x27;%s&#x27; INTERVAL(1 DAY) &quot;&quot;&quot;, deviceId, startDate.atStartOfDay(), endDate.atStartOfDay()); return tdengineService.query(sql, DeviceEnergyTrend.class); &#125;&#125;
数据模型TDengine表结构-- 超级表：设备数据CREATE TABLE IF NOT EXISTS device_data ( ts TIMESTAMP, device_id BIGINT, park_id BIGINT, meter_type TINYINT, -- 1: 2: 3: value DOUBLE, quality TINYINT, status TINYINT) TAGS ( device_type BINARY(20), location BINARY(50));-- 按设备创建子。CREATE TABLE device_001 USING device_data TAGS (&#x27;electricity&#x27;, &#x27;A→号楼&#x27;);-- 园区统计。CREATE TABLE IF NOT EXISTS park_energy ( ts TIMESTAMP, park_id BIGINT, electricity DOUBLE, water DOUBLE, gas DOUBLE);
性能优化1. 批量写入优化@Servicepublic class BatchWriter &#123; private final Queue&lt;EnergyData&gt; buffer = new ConcurrentLinkedQueue&lt;&gt;(); private final AtomicInteger count = new AtomicInteger(0); @Scheduled(fixedRate = 1000) public void flush() &#123; List&lt;EnergyData&gt; batch = new ArrayList&lt;&gt;(); buffer.drainTo(batch, 1000); if (batch.isEmpty()) &#123; return; &#125; // 构建批量插入SQL StringBuilder sql = new StringBuilder(&quot;INSERT INTO &quot;); for (EnergyData data : batch) &#123; sql.append(String.format( &quot;device_%d VALUES (%d, %d, %d, %d, %f, %d, %d) &quot;, data.getDeviceId(), data.getTimestamp(), data.getParkId(), data.getMeterType(), data.getValue(), data.getQuality(), data.getStatus() )); &#125; tdengineService.execute(sql.toString()); &#125;&#125;
2. 缓存优化@Servicepublic class CacheService &#123; @Autowired private RedisTemplate&lt;String, Object&gt; redisTemplate; // 缓存设备统计信息 public EnergyStats getDeviceStats(Long deviceId) &#123; String key = &quot;device:stats:&quot; + deviceId; EnergyStats stats = (EnergyStats) redisTemplate.opsForValue().get(key); if (stats == null) &#123; stats = loadFromTDengine(deviceId); redisTemplate.opsForValue().set(key, stats, 5, TimeUnit.MINUTES); &#125; return stats; &#125; // 缓存园区能耗排。 public List&lt;ParkRank&gt; getParkRanking(int topN) &#123; String key = &quot;park:ranking:&quot; + topN; List&lt;ParkRank&gt; ranking = (List&lt;ParkRank&gt;) redisTemplate.opsForValue().get(key); if (ranking == null) &#123; ranking = calculateRanking(topN); redisTemplate.opsForValue().set(key, ranking, 1, TimeUnit.HOURS); &#125; return ranking; &#125;&#125;
