一、系统架构设备1. 整体架构智慧社区系统架构┌─────────────────────────────────────────────────────────────────。 用户终端 ?? ┌─────────────────────────────────────────────────────────。 ?? App端（住户。 Web端（管理员） 小程序（访客。 ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 应用。 ?? ┌─────────────────────────────────────────────────────────。 ?? 用户服务 设备服务 门禁服务 停车服务 →能耗服务│ ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 数据处理。 ?? ┌─────────────────────────────────────────────────────────。 ?? 数据采集服务 数据清洗服务 数据分析服务 ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 设备接入。 ?? ┌─────────────────────────────────────────────────────────。 ?? MQTT Broker CoAP Server HTTP API ?? └─────────────────────────────────────────────────────────。 →├─────────────────────────────────────────────────────────────────。 设备。 ?? ┌─────────────────────────────────────────────────────────。 ? 门禁设备 停车设备 能耗设备 视频监控 →传感。 └─────────────────────────────────────────────────────────。 →└─────────────────────────────────────────────────────────────────。```### 2. 技术选型| 层级 | 技术选型 | 选型理由 ||------|----------|----------|| **应用。* | SpringBoot + SpringCloud Alibaba | 微服务架构，服务拆分灵活 || **数据采集** | MQTT（EMQX+ Netty | 高并发设备接入，支持百万级连。|| **数据存储** | MySQL + InfluxDB + Redis | 关系数据 + 时序数据 + 缓存 || **消息队列** | RocketMQ | 高可靠性，支持事务消息 || **数据分析** | Flink + Elasticsearch | 实时流处理+ 全文检查|| **前端** | Vue + UniApp | Web+ App端统一开发|---## 二、设备接入架构### 1. MQTT协议接入```java// MQTT设备接入服务@Servicepublic class MqttDeviceService &#123; @Autowired private MqttClient mqttClient; @Autowired private DeviceDataProcessor dataProcessor; /** * 设备连接回调 */ @MqttCallback public void onConnect(String deviceId) &#123; // 1. 更新设备在线状态 deviceService.updateOnlineStatus(deviceId, true); // 2. 记录连接日志 logService.recordConnection(deviceId, &quot;CONNECT&quot;); // 3. 发送欢迎消息 mqttClient.publish(&quot;device/&quot; + deviceId + &quot;/response&quot;, &quot;Welcome&quot;); &#125; /** * 设备断开回调 */ @MqttCallback public void onDisconnect(String deviceId) &#123; // 1. 更新设备离线状态 deviceService.updateOnlineStatus(deviceId, false); // 2. 记录断开日志 logService.recordConnection(deviceId, &quot;DISCONNECT&quot;); // 3. 发送告警（关键设备。 if (isCriticalDevice(deviceId)) &#123; alertService.sendAlert(&quot;关键设备离线: &quot; + deviceId); &#125; &#125; /** * 设备数据上报 */ @MqttSubscribe(topic = &quot;device/+/data&quot;) public void onDeviceData(String topic, String payload) &#123; String deviceId = extractDeviceId(topic); // 1. 解析数据 DeviceData data = JSON.parseObject(payload, DeviceData.class); data.setDeviceId(deviceId); data.setTimestamp(System.currentTimeMillis()); // 2. 数据校验 if (!validateData(data)) &#123; log.warn(&quot;设备数据校验失败: &#123;&#125;&quot;, deviceId); return; &#125; // 3. 数据处理 dataProcessor.process(data); // 4. 存储到时序数据库 influxDBService.saveDeviceData(data); // 5. 触发告警规则检查 alertRuleEngine.check(data); &#125;&#125;
2. 设备管理平台// 设备管理服务@Servicepublic class DeviceManageService &#123; @Autowired private DeviceRepository deviceRepository; @Autowired private RedisTemplate&lt;String, String&gt; redisTemplate; /** * 设备注册 */ public Device registerDevice(DeviceRegisterDTO dto) &#123; // 1. 生成设备ID String deviceId = generateDeviceId(dto.getDeviceType()); // 2. 创建设备记录 Device device = Device.builder() .deviceId(deviceId) .deviceName(dto.getDeviceName()) .deviceType(dto.getDeviceType()) .location(dto.getLocation()) .status(&quot;OFFLINE&quot;) .createdAt(LocalDateTime.now()) .build(); deviceRepository.save(device); // 3. 生成设备密钥 String deviceKey = generateDeviceKey(deviceId); redisTemplate.opsForValue().set(&quot;device:key:&quot; + deviceId, deviceKey); // 4. 返回设备信息 return device; &#125; /** * 设备状态监测 */ public DeviceStatus getDeviceStatus(String deviceId) &#123; // 1. 查询设备基本信息 Device device = deviceRepository.findByDeviceId(deviceId); // 2. 查询实时状态（Redis 和 String status = redisTemplate.opsForValue().get(&quot;device:status:&quot; + deviceId); // 3. 查询最近数据（InfluxDB List&lt;DeviceData&gt; recentData = influxDBService.queryRecentData(deviceId, 10); // 4. 查询告警记录 List&lt;AlertRecord&gt; alerts = alertService.getRecentAlerts(deviceId, 5); return DeviceStatus.builder() .device(device) .onlineStatus(status) .recentData(recentData) .alerts(alerts) .build(); &#125; /** * 设备批量管理 */ public void batchUpdateDevices(List&lt;String&gt; deviceIds, DeviceUpdateDTO dto) &#123; // 1. 批量更新设备配置 deviceRepository.batchUpdate(deviceIds, dto); // 2. 推送配置到设备 for (String deviceId : deviceIds) &#123; mqttClient.publish(&quot;device/&quot; + deviceId + &quot;/config&quot;, JSON.toJSONString(dto)); &#125; // 3. 记录操作日志 logService.recordBatchOperation(&quot;UPDATE_CONFIG&quot;, deviceIds); &#125;&#125;
三、数据处理架构1. 实时数据处理// 实时数据处理。@Servicepublic class RealtimeDataProcessor &#123; @Autowired private RocketMQTemplate rocketMQTemplate; @Autowired private InfluxDBService influxDBService; @Autowired private AlertRuleEngine alertRuleEngine; /** * 处理设备数据 */ public void process(DeviceData data) &#123; // 1. 数据清洗 DeviceData cleanedData = cleanData(data); // 2. 数据转换 DeviceData transformedData = transformData(cleanedData); // 3. 存储到时序数据库 influxDBService.save(transformedData); // 4. 发送到消息队列（异步处理） rocketMQTemplate.send(&quot;device-data-topic&quot;, transformedData); // 5. 告警规则检查 alertRuleEngine.check(transformedData); &#125; /** * 数据清洗 */ private DeviceData cleanData(DeviceData data) &#123; // 1. 去除异常。 if (data.getValue() &lt; 0 || data.getValue() &gt; MAX_VALUE) &#123; data.setValue(null); &#125; // 2. 去除重复数据 if (isDuplicate(data)) &#123; return null; &#125; // 3. 补充缺失字段 if (data.getUnit() == null) &#123; data.setUnit(getDefaultUnit(data.getMetric())); &#125; return data; &#125; /** * 数据转换 */ private DeviceData transformData(DeviceData data) &#123; // 1. 单位转换 if (&quot;temperature&quot;.equals(data.getMetric())) &#123; // 华氏度转摄氏。 if (&quot;F&quot;.equals(data.getUnit())) &#123; data.setValue((data.getValue() - 32) * 5 / 9); data.setUnit(&quot;C&quot;); &#125; &#125; // 2. 时间戳标准化 if (data.getTimestamp() == null) &#123; data.setTimestamp(System.currentTimeMillis()); &#125; return data; &#125;&#125;
2. 时序数据存储// InfluxDB时序数据服务@Servicepublic class InfluxDBService &#123; @Autowired private InfluxDB influxDB; private static final String DATABASE = &quot;smart_community&quot;; /** * 存储设备数据 */ public void save(DeviceData data) &#123; Point point = Point.measurement(&quot;device_data&quot;) .time(data.getTimestamp(), TimeUnit.MILLISECONDS) .tag(&quot;deviceId&quot;, data.getDeviceId()) .tag(&quot;deviceType&quot;, data.getDeviceType()) .tag(&quot;metric&quot;, data.getMetric()) .addField(&quot;value&quot;, data.getValue()) .addField(&quot;unit&quot;, data.getUnit()) .build(); influxDB.write(DATABASE, &quot;autogen&quot;, point); &#125; /** * 查询设备历史数据 */ public List&lt;DeviceData&gt; queryHistory(String deviceId, String metric, long startTime, long endTime) &#123; String query = &quot;SELECT * FROM device_data &quot; + &quot;WHERE deviceId = &#x27;&quot; + deviceId + &quot;&#x27; &quot; + &quot;AND metric = &#x27;&quot; + metric + &quot;&#x27; &quot; + &quot;AND time &gt;= &quot; + startTime + &quot; &quot; + &quot;AND time &lt;= &quot; + endTime; QueryResult result = influxDB.query(new Query(query, DATABASE)); return parseQueryResult(result); &#125; /** * 查询设备聚合数据 */ public DeviceAggregate queryAggregate(String deviceId, String metric, String aggregationType, long startTime, long endTime) &#123; String query = &quot;SELECT &quot; + aggregationType + &quot;(value) FROM device_data &quot; + &quot;WHERE deviceId = &#x27;&quot; + deviceId + &quot;&#x27; &quot; + &quot;AND metric = &#x27;&quot; + metric + &quot;&#x27; &quot; + &quot;AND time &gt;= &quot; + startTime + &quot; &quot; + &quot;AND time &lt;= &quot; + endTime; QueryResult result = influxDB.query(new Query(query, DATABASE)); return parseAggregateResult(result); &#125;&#125;
四、数据分析架构1. 能耗数据分析// 能耗分析服务@Servicepublic class EnergyAnalysisService &#123; @Autowired private InfluxDBService influxDBService; @Autowired private ElasticsearchService esService; /** * 能耗趋势分析 */ public EnergyTrend analyzeTrend(String location, String period) &#123; // 1. 查询历史能耗数据 List&lt;DeviceData&gt; historyData = influxDBService.queryHistory( location, &quot;energy&quot;, getStartTime(period), System.currentTimeMillis() ); // 2. 计算趋势 EnergyTrend trend = EnergyTrend.builder() .totalEnergy(calculateTotal(historyData)) .avgEnergy(calculateAverage(historyData)) .maxEnergy(calculateMax(historyData)) .minEnergy(calculateMin(historyData)) .trendDirection(calculateTrendDirection(historyData)) .build(); return trend; &#125; /** * 能耗异常检查 */ public List&lt;EnergyAnomaly&gt; detectAnomalies(String location) &#123; // 1. 查询最近能耗数据 List&lt;DeviceData&gt; recentData = influxDBService.queryRecentData(location, 100); // 2. 计算基准。 double baseline = calculateBaseline(recentData); // 3. 检测异。 List&lt;EnergyAnomaly&gt; anomalies = new ArrayList&lt;&gt;(); for (DeviceData data : recentData) &#123; if (Math.abs(data.getValue() - baseline) &gt; THRESHOLD) &#123; anomalies.add(EnergyAnomaly.builder() .deviceId(data.getDeviceId()) .value(data.getValue()) .baseline(baseline) .deviation(Math.abs(data.getValue() - baseline)) .timestamp(data.getTimestamp()) .build()); &#125; &#125; return anomalies; &#125; /** * 能耗预。 */ public EnergyPrediction predict(String location, int days) &#123; // 1. 查询历史数据 List&lt;DeviceData&gt; historyData = influxDBService.queryHistory( location, &quot;energy&quot;, System.currentTimeMillis() - 30 * 24 * 60 * 60 * 1000L, System.currentTimeMillis() ); // 2. 使用简单线性回归预。 double[] values = historyData.stream() .mapToDouble(DeviceData::getValue) .toArray(); double slope = calculateSlope(values); double intercept = calculateIntercept(values); // 3. 生成预测数据 List&lt;Double&gt; predictions = new ArrayList&lt;&gt;(); for (int i = 1; i &lt;= days; i++) &#123; predictions.add(intercept + slope * (values.length + i)); &#125; return EnergyPrediction.builder() .predictions(predictions) .confidence(calculateConfidence(values, slope, intercept)) .build(); &#125;&#125;
五、系统性能优化1. 设备接入优化// MQTT连接池优化@Configurationpublic class MqttConfig &#123; @Bean public MqttClient mqttClient() &#123; MqttClient client = new MqttClient(&quot;tcp://emqx:1883&quot;, &quot;server-&quot; + UUID.randomUUID()); MqttConnectOptions options = new MqttConnectOptions(); options.setCleanSession(false); options.setAutomaticReconnect(true); options.setConnectionTimeout(30); options.setKeepAliveInterval(60); options.setMaxInflight(1000); // 最大并发消息数 client.connect(options); return client; &#125;&#125;// 批量数据处理优化@Servicepublic class BatchDataProcessor &#123; private BlockingQueue&lt;DeviceData&gt; dataQueue = new LinkedBlockingQueue&lt;&gt;(10000); @Scheduled(fixedRate = 1000) public void processBatch() &#123; List&lt;DeviceData&gt; batch = new ArrayList&lt;&gt;(); dataQueue.drainTo(batch, 1000); if (batch.isEmpty()) &#123; return; &#125; // 批量存储到InfluxDB influxDBService.batchSave(batch); // 批量发送到MQ rocketMQTemplate.send(&quot;device-data-topic&quot;, batch); &#125;&#125;
2. 数据库优化-- 设备表索引优化CREATE INDEX idx_device_type ON devices (device_type);CREATE INDEX idx_device_location ON devices (location);CREATE INDEX idx_device_status ON devices (status);-- 设备数据表分区（按时间）CREATE TABLE device_data ( id BIGINT PRIMARY KEY, device_id VARCHAR(50), metric VARCHAR(50), value DECIMAL(10,2), timestamp BIGINT, created_at DATETIME) PARTITION BY RANGE (timestamp) ( PARTITION p202601 VALUES LESS THAN (1704067200000), PARTITION p202602 VALUES LESS THAN (1706745600000), PARTITION p202603 VALUES LESS THAN (1709424000000));
六、项目踩坑记。1. 设备连接数瓶。问题描述 - 5000+设备同时连接，MQTT Broker连接数达到上。- 设备频繁断线重连，导致连接风险解决方案 &#96;&#96;&#96;java&#x2F;&#x2F; 1. 增加MQTT Broker集群&#x2F;&#x2F; EMQX集群部署，支持百万级连接 &#x2F;&#x2F; 2. 设备连接限流@Componentpublic class ConnectionLimiter { private RateLimiter rateLimiter = RateLimiter.create(100); // 每秒100个连。 public boolean tryConnect(String deviceId) { if (rateLimiter.tryAcquire()) { return true; } // 等待重试 return false; }
} &#x2F;&#x2F; 3. 设备心跳优化&#x2F;&#x2F; 心跳间隔离0秒调整为60秒，减少网络负载 ### 2. 数据存储瓶颈**问题描述** - 日均100万条数据，MySQL单表性能下降- 查询历史数据耗时超过10.**解决方案** ```java// 1. 引入时序数据库InfluxDB// 时序数据存储到InfluxDB，关系数据存储到MySQL// 2. 数据冷热分离// 最天数据存储到Redis，历史数据存储到InfluxDB// 3. 数据聚合预计。@Scheduled(cron = &quot;0 0 1 * * &quot;) // 每天凌晨1.public void aggregateDailyData() &#123; // 预计算每日能耗统。 energyService.aggregateDaily(); // 预计算每日告警统。 alertService.aggregateDaily();&#125;
项目效果
指标 优化工 优化工 提升
设备接入延迟 500ms 50ms 10.
数据查询速度 10. 100ms 100.
系统并发能力 1000设备 10000设备 10.
数据存储成本 100GB&#x2F; 10GB&#x2F; 降低90%
总结智慧社区系统的核心挑战是。海量设备接入、实时数据处理、大数据量存。。关键技术点。
设备接入：MQTT协议 + EMQX集群 + 连接限流 数据存储：时序数据库InfluxDB + 冷热分离 数据处理：批量处理+ 异步处理 + 预计。4. 数据分析：趋势分析+ 异常检查+ 预测
这些经验对后续智慧矿山项目有重要参考价值

前言架构设计题是面试中最能体现技术能力的部分，考察候选人的系统设计能力、扩展性思维和技术选型能力。024年我参与过多个系统的架构设计，包括短链系统、分布式ID生成器、秒杀系统等，这篇文章整理了架构设计最核心的面试题。一、短链系统设备1. 短链系统架构短链系统架构┌─────────────────────────────────────────────────────────────────。 用户请求 ?? POST /api/shorten (长链路短链路 ?? GET /&#123;shortCode&#125; (短链路长链路 →├─────────────────────────────────────────────────────────────────。 API网关 ?? - 限流、熔断、日。 →├─────────────────────────────────────────────────────────────────。 短链服务 ?? - 生成短码 ?? - 存储映射关系 →├─────────────────────────────────────────────────────────────────。 缓存。 - Redis: shortCode 和 longUrl →├─────────────────────────────────────────────────────────────────。 存储。 - MySQL: 存储完整映射关系 →└─────────────────────────────────────────────────────────────────。```### 2. 短码生成算法```java@Componentpublic class ShortCodeGenerator &#123; /** * 字符集：62个字符（a-z, A-Z, 0-9. */ private static final String CHARS = &quot;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&quot;; private static final int LENGTH = 6; // 短码长度 /** * 基于自增ID生成短码 */ public String generate(Long id) &#123; StringBuilder sb = new StringBuilder(); while (id &gt; 0) &#123; int index = (int) (id % 62); sb.append(CHARS.charAt(index)); id = id / 62; &#125; // 不足6位补前导字符 while (sb.length() &lt; LENGTH) &#123; sb.append(CHARS.charAt(0)); &#125; return sb.reverse().toString(); &#125; /** * 短码解码 */ public Long decode(String shortCode) &#123; long id = 0; for (int i = 0; i &lt; shortCode.length(); i++) &#123; char c = shortCode.charAt(i); int index = CHARS.indexOf(c); id = id * 62 + index; &#125; return id; &#125; /** * 基于哈希的短码生成（防碰撞） */ public String generateByHash(String longUrl) &#123; // 使用MD5哈希 String hash = DigestUtils.md5Hex(longUrl); // 取前12位，分成2组，每组6. String part1 = hash.substring(0, 12); // 转换为短链 StringBuilder sb = new StringBuilder(); for (int i = 0; i &lt; 6; i++) &#123; int index = Integer.parseInt(part1.substring(i * 2, i * 2 + 2), 16) % 62; sb.append(CHARS.charAt(index)); &#125; return sb.toString(); &#125;&#125;
3. 核心服务实现@Servicepublic class ShortUrlService &#123; @Autowired private ShortCodeGenerator codeGenerator; @Autowired private StringRedisTemplate redisTemplate; @Autowired private ShortUrlRepository shortUrlRepository; private static final String CACHE_KEY_PREFIX = &quot;short:url:&quot;; private static final long CACHE_EXPIRE_DAYS = 30; /** * 生成短链路 */ public String shorten(String longUrl) &#123; // 1. 检查是否已存在 String existingCode = shortUrlRepository.findShortCodeByLongUrl(longUrl); if (existingCode != null) &#123; return buildShortUrl(existingCode); &#125; // 2. 生成短码 String shortCode = generateUniqueCode(); // 3. 保存到数据库 ShortUrl shortUrl = ShortUrl.builder() .shortCode(shortCode) .longUrl(longUrl) .createdAt(LocalDateTime.now()) .expireAt(LocalDateTime.now().plusDays(30)) .build(); shortUrlRepository.save(shortUrl); // 4. 缓存 redisTemplate.opsForValue().set( CACHE_KEY_PREFIX + shortCode, longUrl, CACHE_EXPIRE_DAYS, TimeUnit.DAYS ); return buildShortUrl(shortCode); &#125; /** * 获取原始链接 */ public String expand(String shortCode) &#123; // 1. 先查缓存 String longUrl = redisTemplate.opsForValue().get(CACHE_KEY_PREFIX + shortCode); if (longUrl != null) &#123; return longUrl; &#125; // 2. 查数据库 ShortUrl shortUrl = shortUrlRepository.findByShortCode(shortCode); if (shortUrl == null) &#123; throw new BusinessException(&quot;短链接不存在&quot;); &#125; // 3. 更新缓存 redisTemplate.opsForValue().set( CACHE_KEY_PREFIX + shortCode, shortUrl.getLongUrl(), CACHE_EXPIRE_DAYS, TimeUnit.DAYS ); return shortUrl.getLongUrl(); &#125; /** * 生成唯一短码 */ private String generateUniqueCode() &#123; while (true) &#123; // 方案1：使用分布式ID Long id = snowflakeIdGenerator.nextId(); String code = codeGenerator.generate(id); // 检查唯一、 if (!shortUrlRepository.existsByShortCode(code)) &#123; return code; &#125; &#125; &#125; private String buildShortUrl(String shortCode) &#123; return &quot;https://short.example.com/&quot; + shortCode; &#125;&#125;
二、分布式ID生成。1. 分布式ID方案对比
方案 原理 优点 缺点 适用场景
UUID 随机生成 无中心化 无序、索引效率低 非主键场景
*数据库自动 数据库主。 简单、有。 单点故障、性能瓶颈 中小规模
雪花算法 时间机器ID+序队列 有序、高性能 时钟回拨问题 大规模分布式
Redis自增 Redis原子操作 高性能、有。 依赖Redis 需要高并发
2. 雪花算法实现@Componentpublic class SnowflakeIdGenerator &#123; /** * 起始时间戳（2024-01-01. */ private static final long START_TIMESTAMP = 1704067200000L; /** * 机器ID位数 */ private static final long WORKER_ID_BITS = 5L; /** * 数据中心ID位数 */ private static final long DATA_CENTER_ID_BITS = 5L; /** * 序列号位。 */ private static final long SEQUENCE_BITS = 12L; /** * 最大机器ID */ private static final long MAX_WORKER_ID = ~(-1L &lt;&lt; WORKER_ID_BITS); /** * 最大数据中心ID */ private static final long MAX_DATA_CENTER_ID = ~(-1L &lt;&lt; DATA_CENTER_ID_BITS); /** * 序列号掩。 */ private static final long MAX_SEQUENCE = ~(-1L &lt;&lt; SEQUENCE_BITS); /** * 机器ID左移位数 */ private static final long WORKER_ID_SHIFT = SEQUENCE_BITS; /** * 数据中心ID左移位数 */ private static final long DATA_CENTER_ID_SHIFT = SEQUENCE_BITS + WORKER_ID_BITS; /** * 时间戳左移位。 */ private static final long TIMESTAMP_SHIFT = DATA_CENTER_ID_SHIFT + DATA_CENTER_ID_BITS; private final long workerId; private final long dataCenterId; private long sequence = 0L; private long lastTimestamp = -1L; public SnowflakeIdGenerator( @Value(&quot;$&#123;snowflake.worker-id:0&#125;&quot;) long workerId, @Value(&quot;$&#123;snowflake.data-center-id:0&#125;&quot;) long dataCenterId ) &#123; if (workerId &gt; MAX_WORKER_ID || workerId &lt; 0) &#123; throw new IllegalArgumentException(&quot;Worker ID超出范围&quot;); &#125; if (dataCenterId &gt; MAX_DATA_CENTER_ID || dataCenterId &lt; 0) &#123; throw new IllegalArgumentException(&quot;Data Center ID超出范围&quot;); &#125; this.workerId = workerId; this.dataCenterId = dataCenterId; &#125; /** * 生成下一个ID */ public synchronized long nextId() &#123; long timestamp = System.currentTimeMillis(); // 时钟回拨处理 if (timestamp &lt; lastTimestamp) &#123; // 等待时间追上 while (timestamp &lt; lastTimestamp) &#123; timestamp = System.currentTimeMillis(); &#125; &#125; // 同一毫秒杀 if (timestamp == lastTimestamp) &#123; sequence = (sequence + 1) &amp; MAX_SEQUENCE; // 序列号溢出，等待下一毫秒 if (sequence == 0) &#123; timestamp = waitNextMillis(timestamp); &#125; &#125; else &#123; sequence = 0L; &#125; lastTimestamp = timestamp; // 组合ID return ((timestamp - START_TIMESTAMP) &lt;&lt; TIMESTAMP_SHIFT) | (dataCenterId &lt;&lt; DATA_CENTER_ID_SHIFT) | (workerId &lt;&lt; WORKER_ID_SHIFT) | sequence; &#125; private long waitNextMillis(long timestamp) &#123; while (timestamp == lastTimestamp) &#123; timestamp = System.currentTimeMillis(); &#125; return timestamp; &#125;&#125;
3. Redis自增方案@Componentpublic class RedisIdGenerator &#123; @Autowired private StringRedisTemplate redisTemplate; private static final String ID_KEY_PREFIX = &quot;id:generator:&quot;; /** * 获取下一个ID */ public long nextId(String key) &#123; String redisKey = ID_KEY_PREFIX + key; // 原子递增 Long id = redisTemplate.opsForValue().increment(redisKey); if (id == 1) &#123; // 首次创建，设置过期时序 redisTemplate.expire(redisKey, 1, TimeUnit.DAYS); &#125; return id != null id : -1; &#125; /** * 批量获取ID */ public List&lt;Long&gt; nextIds(String key, int count) &#123; String redisKey = ID_KEY_PREFIX + key; // 使用Lua脚本批量获取 String luaScript = &quot;&quot;&quot; local key = KEYS[1] local count = tonumber(ARGV[1]) local result = &#123;&#125; for i=1,count do table.insert(result, redis.call(&#x27;INCR&#x27;, key)) end return result &quot;&quot;&quot;; List&lt;Long&gt; ids = redisTemplate.execute( new DefaultRedisScript&lt;&gt;(luaScript, List.class), Collections.singletonList(redisKey), String.valueOf(count) ); // 设置过期时间 redisTemplate.expire(redisKey, 1, TimeUnit.DAYS); return ids; &#125;&#125;
三、秒杀系统设计1. 秒杀系统架构秒杀系统架构┌─────────────────────────────────────────────────────────────────。 用户请求 ?? GET /api/seckill/&#123;productId&#125; ?? POST /api/seckill/order →├─────────────────────────────────────────────────────────────────。 网关。 ?? - 限流（令牌桶。 ?? - 黑白名单 ?? - 参数校验 →├─────────────────────────────────────────────────────────────────。 服务。 ?? - 库存检查（Redis? ?? - 订单创建 ?? - 异步处理 →├─────────────────────────────────────────────────────────────────。 缓存。 ?? - Redis库存预扣。 ?? - 热点数据缓存 →├─────────────────────────────────────────────────────────────────。 消息队列 ?? - RocketMQ: 异步下单 →├─────────────────────────────────────────────────────────────────。 存储。 ? - MySQL: 订单存储 - Redis: 库存缓存 →└─────────────────────────────────────────────────────────────────。```### 2. 秒杀核心代码```java@Servicepublic class SeckillService &#123; @Autowired private StringRedisTemplate redisTemplate; @Autowired private RocketMQTemplate rocketMQTemplate; @Autowired private ProductRepository productRepository; private static final String STOCK_KEY = &quot;seckill:stock:&quot;; private static final String USER_LIMIT_KEY = &quot;seckill:user:&quot;; /** * 秒杀下单 */ public SeckillResult seckill(Long userId, Long productId) &#123; // 1. 检查活动状态 Product product = productRepository.findById(productId).orElseThrow(); if (!product.isActive()) &#123; return SeckillResult.failure(&quot;活动未开始或已结构); &#125; // 2. 检查用户限。 String userLimitKey = USER_LIMIT_KEY + productId + &quot;:&quot; + userId; Long count = redisTemplate.opsForValue().increment(userLimitKey); if (count != null &amp;&amp; count &gt; product.getBuyLimit()) &#123; return SeckillResult.failure(&quot;超出限购数量&quot;); &#125; redisTemplate.expire(userLimitKey, product.getEndTime().toInstant().toEpochMilli() - System.currentTimeMillis(), TimeUnit.MILLISECONDS); // 3. 预扣减数据库 String stockKey = STOCK_KEY + productId; Long stock = redisTemplate.opsForValue().decrement(stockKey); if (stock == null || stock &lt; 0) &#123; // 库存不足，恢复用户限购计。 redisTemplate.opsForValue().decrement(userLimitKey); return SeckillResult.failure(&quot;库存不足&quot;); &#125; // 4. 发送异步消息 SeckillMessage message = SeckillMessage.builder() .userId(userId) .productId(productId) .productName(product.getName()) .price(product.getSeckillPrice()) .build(); rocketMQTemplate.send(&quot;seckill-topic&quot;, MessageBuilder.withPayload(message).build()); return SeckillResult.success(&quot;排队。); &#125; /** * 异步处理订单 */ @RocketMQMessageListener(topic = &quot;seckill-topic&quot;, consumerGroup = &quot;seckill-consumer&quot;) public class SeckillConsumer implements RocketMQListener&lt;SeckillMessage&gt; &#123; @Autowired private OrderRepository orderRepository; @Override public void onMessage(SeckillMessage message) &#123; try &#123; // 创建订单 Order order = Order.builder() .orderId(snowflakeIdGenerator.nextId()) .userId(message.getUserId()) .productId(message.getProductId()) .productName(message.getProductName()) .price(message.getPrice()) .status(&quot;PENDING&quot;) .createdAt(LocalDateTime.now()) .build(); orderRepository.save(order); // 更新数据库数据库 productRepository.decrementStock(message.getProductId()); // 发送通知 notificationService.sendSeckillSuccess(message.getUserId(), order.getOrderId()); &#125; catch (Exception e) &#123; // 失败回滚库存 redisTemplate.opsForValue().increment(STOCK_KEY + message.getProductId()); log.error(&quot;秒杀订单创建失败&quot;, e); &#125; &#125; &#125;&#125;
3. 限流实现@Componentpublic class SeckillRateLimiter &#123; @Autowired private StringRedisTemplate redisTemplate; /** * 令牌桶限。 */ public boolean tryAcquire(Long productId, int limitPerSecond) &#123; String key = &quot;seckill:rate:&quot; + productId; long now = System.currentTimeMillis(); // Lua脚本实现令牌。 String luaScript = &quot;&quot;&quot; local key = KEYS[1] local limit = tonumber(ARGV[1]) local now = tonumber(ARGV[2]) -- 获取当前令牌。 local tokens = tonumber(redis.call(&#x27;GET&#x27;, key .. &#x27;:tokens&#x27;)) or 0 local lastTime = tonumber(redis.call(&#x27;GET&#x27;, key .. &#x27;:time&#x27;)) or now -- 计算新令牌数 local elapsed = now - lastTime local newTokens = math.min(limit, tokens + elapsed * limit / 1000) if newTokens &gt;= 1 then redis.call(&#x27;SET&#x27;, key .. &#x27;:tokens&#x27;, newTokens - 1) redis.call(&#x27;SET&#x27;, key .. &#x27;:time&#x27;, now) return 1 else return 0 end &quot;&quot;&quot;; Long result = redisTemplate.execute( new DefaultRedisScript&lt;&gt;(luaScript, Long.class), Collections.singletonList(key), String.valueOf(limitPerSecond), String.valueOf(now) ); return result != null &amp;&amp; result == 1; &#125;&#125;
四、URL短链系统进阶设计1. 高可用架构短链系统高可用架构┌─────────────────────────────────────────────────────────────────────┐│ 客户端请求 ││ POST /api/shorten | GET /&#123;shortCode&#125; │├─────────────────────────────────────────────────────────────────────┤│ CDN层 ││ - 缓存热门短链访问 ││ - 边缘节点就近响应 │├─────────────────────────────────────────────────────────────────────┤│ 负载均衡层 ││ - Nginx / SLB ││ - 健康检查、流量分发 │├─────────────────────────────────────────────────────────────────────┤│ 短链服务集群 ││ - 多个服务实例 ││ - 无状态设计，支持水平扩展 │├─────────────────────────────────────────────────────────────────────┤│ Redis集群 ││ - 主从复制、哨兵模式 ││ - 缓存热点数据 │├─────────────────────────────────────────────────────────────────────┤│ MySQL集群 ││ - 主从复制、读写分离 ││ - 数据分片（按shortCode哈希） │└─────────────────────────────────────────────────────────────────────┘
2. 性能优化策略/** * 短链系统性能优化 */@Servicepublic class ShortUrlOptimizedService &#123; /** * 批量生成短链 */ public List&lt;String&gt; batchShorten(List&lt;String&gt; longUrls) &#123; List&lt;String&gt; results = new ArrayList&lt;&gt;(); // 1. 先检查缓存中已存在的URL Map&lt;String, String&gt; existingMap = checkCacheBatch(longUrls); // 2. 批量生成新短码 List&lt;String&gt; newUrls = longUrls.stream() .filter(url -&gt; !existingMap.containsKey(url)) .collect(Collectors.toList()); List&lt;String&gt; newCodes = batchGenerateCodes(newUrls.size()); // 3. 批量保存到数据库 batchSaveToDb(newUrls, newCodes); // 4. 批量更新缓存 batchUpdateCache(newUrls, newCodes); // 5. 组装结果 for (String url : longUrls) &#123; String code = existingMap.getOrDefault(url, findCodeByUrl(url, newUrls, newCodes)); results.add(buildShortUrl(code)); &#125; return results; &#125; /** * 热点短链预热 */ @Scheduled(cron = &quot;0 0 8 * * ?&quot;) public void hotUrlWarmup() &#123; // 获取访问量TOP100的短链 List&lt;ShortUrl&gt; hotUrls = shortUrlRepository.findTop100ByAccessCount(); // 预热到本地缓存 for (ShortUrl url : hotUrls) &#123; localCache.put(CACHE_KEY_PREFIX + url.getShortCode(), url.getLongUrl()); &#125; &#125;&#125;
3. 监控与告警/** * 短链系统监控指标 */@Componentpublic class ShortUrlMetrics &#123; private final Counter shortenCounter; private final Counter expandCounter; private final Counter cacheHitCounter; private final Counter cacheMissCounter; private final Timer latencyTimer; public ShortUrlMetrics(MeterRegistry registry) &#123; this.shortenCounter = Counter.builder(&quot;short_url_shorten_total&quot;) .description(&quot;短链生成总数&quot;) .register(registry); this.expandCounter = Counter.builder(&quot;short_url_expand_total&quot;) .description(&quot;短链解析总数&quot;) .register(registry); this.cacheHitCounter = Counter.builder(&quot;short_url_cache_hit_total&quot;) .description(&quot;缓存命中数&quot;) .register(registry); this.cacheMissCounter = Counter.builder(&quot;short_url_cache_miss_total&quot;) .description(&quot;缓存未命中数&quot;) .register(registry); this.latencyTimer = Timer.builder(&quot;short_url_request_latency&quot;) .description(&quot;请求延迟&quot;) .register(registry); &#125; public void recordShorten() &#123; shortenCounter.increment(); &#125; public void recordExpand() &#123; expandCounter.increment(); &#125; public void recordCacheHit() &#123; cacheHitCounter.increment(); &#125; public void recordCacheMiss() &#123; cacheMissCounter.increment(); &#125; public void recordLatency(long millis) &#123; latencyTimer.record(millis, TimeUnit.MILLISECONDS); &#125;&#125;
五、分布式ID进阶设计1. ID生成器高可用方案/** * 分布式ID生成器（高可用版本） */@Componentpublic class HighAvailableIdGenerator &#123; @Autowired private SnowflakeIdGenerator snowflakeIdGenerator; @Autowired private RedisIdGenerator redisIdGenerator; @Autowired private JdbcIdGenerator jdbcIdGenerator; /** * 优先级策略：Snowflake &gt; Redis &gt; JDBC */ public long nextId(String key) &#123; try &#123; return snowflakeIdGenerator.nextId(); &#125; catch (Exception e) &#123; log.warn(&quot;Snowflake ID生成失败，切换到Redis: &#123;&#125;&quot;, e.getMessage()); &#125; try &#123; return redisIdGenerator.nextId(key); &#125; catch (Exception e) &#123; log.warn(&quot;Redis ID生成失败，切换到JDBC: &#123;&#125;&quot;, e.getMessage()); &#125; return jdbcIdGenerator.nextId(key); &#125;&#125;/** * 数据库自增ID生成器 */@Componentpublic class JdbcIdGenerator &#123; @Autowired private JdbcTemplate jdbcTemplate; private static final String TABLE_NAME = &quot;id_generator&quot;; public synchronized long nextId(String key) &#123; // 1. 更新并获取ID String sql = &quot;UPDATE &quot; + TABLE_NAME + &quot; SET current_id = current_id + 1 WHERE id_key = ?&quot;; jdbcTemplate.update(sql, key); // 2. 查询最新ID String querySql = &quot;SELECT current_id FROM &quot; + TABLE_NAME + &quot; WHERE id_key = ?&quot;; return jdbcTemplate.queryForObject(querySql, Long.class, key); &#125;&#125;
2. ID生成器性能对比ID生成器性能对比：┌──────────────┬────────────────┬──────────────┬────────────────┐│ 方案 │ QPS │ 可用性 │ 特点 │├──────────────┼────────────────┼──────────────┼────────────────┤│ Snowflake │ 100000+ │ 99.99% │ 时钟回拨风险 ││ Redis │ 50000+ │ 99.9% │ 依赖Redis ││ JDBC │ 1000+ │ 99.99% │ 性能瓶颈 │└──────────────┴────────────────┴──────────────┴────────────────┘
六、秒杀系统进阶设计1. 多级限流架构/** * 秒杀系统多级限流 */@Servicepublic class MultiLevelRateLimiter &#123; @Autowired private StringRedisTemplate redisTemplate; /** * 多级限流检查 */ public RateLimitResult check(Long userId, Long productId, String ip) &#123; // 1. IP级限流：每秒100次 if (!checkIpLimit(ip)) &#123; return RateLimitResult.failure(&quot;IP访问过于频繁&quot;); &#125; // 2. 用户级限流：每分钟10次 if (!checkUserLimit(userId)) &#123; return RateLimitResult.failure(&quot;用户访问过于频繁&quot;); &#125; // 3. 商品级限流：每秒1000次 if (!checkProductLimit(productId)) &#123; return RateLimitResult.failure(&quot;商品访问过于频繁&quot;); &#125; // 4. 全局限流：每秒10000次 if (!checkGlobalLimit()) &#123; return RateLimitResult.failure(&quot;系统繁忙&quot;); &#125; return RateLimitResult.success(); &#125; private boolean checkIpLimit(String ip) &#123; String key = &quot;rate:ip:&quot; + ip; return checkLimit(key, 100, 1); &#125; private boolean checkUserLimit(Long userId) &#123; String key = &quot;rate:user:&quot; + userId; return checkLimit(key, 10, 60); &#125; private boolean checkProductLimit(Long productId) &#123; String key = &quot;rate:product:&quot; + productId; return checkLimit(key, 1000, 1); &#125; private boolean checkGlobalLimit() &#123; String key = &quot;rate:global&quot;; return checkLimit(key, 10000, 1); &#125; private boolean checkLimit(String key, int limit, int seconds) &#123; Long count = redisTemplate.opsForValue().increment(key); if (count == 1) &#123; redisTemplate.expire(key, seconds, TimeUnit.SECONDS); &#125; return count != null &amp;&amp; count &lt;= limit; &#125;&#125;
2. 库存一致性保障/** * 库存一致性检查器 */@Componentpublic class StockConsistencyChecker &#123; @Autowired private StringRedisTemplate redisTemplate; @Autowired private ProductRepository productRepository; /** * 定期检查库存一致性 */ @Scheduled(cron = &quot;0 */5 * * * ?&quot;) public void checkStockConsistency() &#123; List&lt;Product&gt; products = productRepository.findAllActiveSeckillProducts(); for (Product product : products) &#123; Integer redisStock = getRedisStock(product.getId()); Integer dbStock = product.getStock(); if (!redisStock.equals(dbStock)) &#123; log.warn(&quot;库存不一致: productId=&#123;&#125;, redis=&#123;&#125;, db=&#123;&#125;&quot;, product.getId(), redisStock, dbStock); // 以数据库为准修正Redis redisTemplate.opsForValue().set( STOCK_KEY + product.getId(), dbStock.toString() ); &#125; &#125; &#125; /** * 实时库存同步（数据库更新后触发） */ @TransactionalEventListener public void onStockUpdate(StockUpdateEvent event) &#123; redisTemplate.opsForValue().set( STOCK_KEY + event.getProductId(), event.getStock().toString() ); &#125;&#125;
