五、性能测试与监控1. 秒杀系统性能测试/** * 秒杀系统压测结果 */public class SeckillPerformanceTest &#123;        /**     * 压测场景：10万用户同时抢购1000件商品     */    @Test    public void testSeckillPerformance() &#123;        // 压测结果：        // QPS: 50000        // 成功率: 99.9%        // 平均响应时间: 50ms        // P99响应时间: 150ms        // 数据库QPS: 1000 (异步下单后)    &#125;&#125;/** * 性能对比表 */// | 方案 | QPS | 成功率 | 平均响应时间 | 数据库QPS |// |------|-----|--------|--------------|-----------|// | 裸奔(直接DB) | 500 | 95% | 2000ms | 1000 |// | Redis缓存 | 2000 | 98% | 500ms | 500 |// | 完整版(多级缓存+MQ) | 50000 | 99.9% | 50ms | 100 |

2. 限流效果测试/** * 限流效果测试 */@Servicepublic class RateLimitTest &#123;        /**     * 测试令牌桶限流效果     */    @Test    public void testTokenBucket() &#123;        RateLimiter limiter = new RateLimiter();                // 设置限流：每秒1000个请求，桶容量5000        int successCount = 0;        int failCount = 0;                for (int i = 0; i &lt; 10000; i++) &#123;            if (limiter.tryAcquire(&quot;test&quot;, 1000, 5000)) &#123;                successCount++;            &#125; else &#123;                failCount++;            &#125;        &#125;                // 结果：约1000个成功，9000个失败（1秒内）        System.out.println(&quot;成功: &quot; + successCount + &quot;, 失败: &quot; + failCount);    &#125;&#125;

3. 监控指标/** * 高并发系统监控指标 */@Componentpublic class HighConcurrencyMetrics &#123;        private final Counter requestCounter;    private final Counter successCounter;    private final Counter failCounter;    private final Timer latencyTimer;    private final Gauge stockGauge;    private final Gauge cacheHitRateGauge;    private final Gauge rateLimitRejectGauge;    public HighConcurrencyMetrics(MeterRegistry registry) &#123;        this.requestCounter = Counter.builder(&quot;hc_request_total&quot;)            .description(&quot;请求总数&quot;)            .register(registry);                this.successCounter = Counter.builder(&quot;hc_success_total&quot;)            .description(&quot;成功请求数&quot;)            .register(registry);                this.failCounter = Counter.builder(&quot;hc_fail_total&quot;)            .description(&quot;失败请求数&quot;)            .tag(&quot;reason&quot;, &quot;unknown&quot;)            .register(registry);                this.latencyTimer = Timer.builder(&quot;hc_request_latency&quot;)            .description(&quot;请求延迟&quot;)            .register(registry);                this.stockGauge = Gauge.builder(&quot;hc_stock_remaining&quot;)            .description(&quot;剩余库存&quot;)            .register(registry);                this.cacheHitRateGauge = Gauge.builder(&quot;hc_cache_hit_rate&quot;)            .description(&quot;缓存命中率&quot;)            .register(registry);                this.rateLimitRejectGauge = Gauge.builder(&quot;hc_rate_limit_reject&quot;)            .description(&quot;限流拒绝数&quot;)            .register(registry);    &#125;        public void recordRequest() &#123;        requestCounter.increment();    &#125;        public void recordSuccess() &#123;        successCounter.increment();    &#125;        public void recordFail(String reason) &#123;        failCounter.increment();    &#125;        public void recordLatency(long millis) &#123;        latencyTimer.record(millis, TimeUnit.MILLISECONDS);    &#125;        public void setStock(int stock) &#123;        stockGauge.set(stock);    &#125;&#125;

4. 告警规则# Prometheus告警规则groups:- name: high-concurrency-alerts  rules:  - alert: HighRequestRate    expr: rate(hc_request_total[1m]) &gt; 10000    for: 1m    labels:      severity: warning    annotations:      summary: &quot;请求量过高&quot;      description: &quot;当前QPS: &#123;&#123; $value &#125;&#125;&quot;    - alert: LowSuccessRate    expr: hc_success_total / hc_request_total &lt; 0.99    for: 1m    labels:      severity: critical    annotations:      summary: &quot;成功率过低&quot;      description: &quot;成功率: &#123;&#123; $value &#125;&#125;&quot;    - alert: HighLatency    expr: avg(hc_request_latency_seconds) &gt; 1    for: 1m    labels:      severity: warning    annotations:      summary: &quot;响应时间过高&quot;      description: &quot;平均延迟: &#123;&#123; $value &#125;&#125;s&quot;    - alert: StockLow    expr: hc_stock_remaining &lt; 100    for: 0m    labels:      severity: info    annotations:      summary: &quot;库存不足&quot;      description: &quot;剩余库存: &#123;&#123; $value &#125;&#125;&quot;    - alert: HighRateLimitReject    expr: rate(hc_rate_limit_reject[1m]) &gt; 1000    for: 1m    labels:      severity: warning    annotations:      summary: &quot;限流拒绝过多&quot;      description: &quot;拒绝数: &#123;&#123; $value &#125;&#125;&quot;

六、常见问题排查1. 秒杀超卖问题// 问题：库存扣减后订单创建失败，导致库存不一致// 排查步骤：// 1. 检查Redis和数据库库存是否一致// 2. 检查MQ消费是否有失败// 3. 检查异常处理是否正确回滚// 解决方案：@Servicepublic class StockConsistencyChecker &#123;        @Scheduled(cron = &quot;0 */5 * * * ?&quot;)    public void checkStockConsistency() &#123;        // 对比Redis和数据库库存        List&lt;Long&gt; productIds = productMapper.selectActiveProductIds();                for (Long productId : productIds) &#123;            Integer redisStock = getRedisStock(productId);            Integer dbStock = getDbStock(productId);                        if (!redisStock.equals(dbStock)) &#123;                log.warn(&quot;库存不一致: productId=&#123;&#125;, redis=&#123;&#125;, db=&#123;&#125;&quot;,                     productId, redisStock, dbStock);                // 以数据库为准修正Redis                redisTemplate.opsForValue().set(&quot;stock:&quot; + productId, dbStock.toString());            &#125;        &#125;    &#125;&#125;

2. 缓存击穿问题// 问题：热点Key过期瞬间，大量请求穿透到数据库// 排查步骤：// 1. 检查缓存过期时间设置// 2. 检查热点Key列表// 3. 检查本地缓存配置// 解决方案：@Servicepublic class CacheBreakdownHandler &#123;        @Autowired    private Cache&lt;String, Object&gt; localCache;        @Autowired    private StringRedisTemplate redisTemplate;        public Object getWithLock(String key) &#123;        // 1. 先查本地缓存        Object localValue = localCache.getIfPresent(key);        if (localValue != null) &#123;            return localValue;        &#125;                // 2. 分布式锁防止并发穿透        String lockKey = &quot;lock:cache:&quot; + key;        RLock lock = redissonClient.getLock(lockKey);                try &#123;            if (lock.tryLock(3, 10, TimeUnit.SECONDS)) &#123;                // 双重检查                localValue = localCache.getIfPresent(key);                if (localValue != null) &#123;                    return localValue;                &#125;                                // 查Redis                String redisValue = redisTemplate.opsForValue().get(key);                if (redisValue != null) &#123;                    Object parsedValue = JSON.parse(redisValue);                    localCache.put(key, parsedValue);                    return parsedValue;                &#125;                                // 查数据库（限流保护）                if (!dbRateLimiter.tryAcquire()) &#123;                    throw new BusinessException(&quot;系统繁忙&quot;);                &#125;                                Object dbValue = loadFromDb(key);                if (dbValue != null) &#123;                    redisTemplate.opsForValue().set(key, JSON.toJSONString(dbValue), 30, TimeUnit.MINUTES);                    localCache.put(key, dbValue);                &#125;                return dbValue;            &#125; else &#123;                // 获取锁失败，返回空或默认值                return null;            &#125;        &#125; finally &#123;            lock.unlock();        &#125;    &#125;&#125;

3. 限流绕过问题// 问题：恶意用户绕过限流// 排查步骤：// 1. 检查限流Key是否正确// 2. 检查是否有IP伪造// 3. 检查是否有请求频率异常// 解决方案：@Servicepublic class AdvancedRateLimiter &#123;        @Autowired    private StringRedisTemplate redisTemplate;        /**     * 多维度限流     */    public boolean tryAcquire(String userId, String ip, String deviceId) &#123;        // 用户维度限流        boolean userLimit = checkLimit(&quot;rate:user:&quot; + userId, 10, 60);        // IP维度限流        boolean ipLimit = checkLimit(&quot;rate:ip:&quot; + ip, 100, 60);        // 设备维度限流        boolean deviceLimit = checkLimit(&quot;rate:device:&quot; + deviceId, 10, 60);                return userLimit &amp;&amp; ipLimit &amp;&amp; deviceLimit;    &#125;        private boolean checkLimit(String key, int limit, int seconds) &#123;        Long count = redisTemplate.opsForValue().increment(key);        if (count == 1) &#123;            redisTemplate.expire(key, seconds, TimeUnit.SECONDS);        &#125;        return count &lt;= limit;    &#125;&#125;

七、生产环境配置1. Nginx限流配置http &#123;    # 限流配置    limit_req_zone $binary_remote_addr zone=seckill:10m rate=1000r/s;        server &#123;        location /api/seckill &#123;            # 限流：每秒1000个请求，桶容量5000            limit_req zone=seckill burst=5000 nodelay;                        # 连接数限制            limit_conn seckill_conn 1000;                        proxy_pass http://seckill-service;        &#125;    &#125;&#125;

2. Redis集群配置@Configurationpublic class RedisClusterConfig &#123;        @Bean    public RedissonClient redissonClient() &#123;        Config config = new Config();        config.useClusterServers()            .addNodeAddress(                &quot;redis://redis-0:6379&quot;,                &quot;redis://redis-1:6379&quot;,                &quot;redis://redis-2:6379&quot;            )            .setMasterConnectionPoolSize(100)            .setSlaveConnectionPoolSize(100)            .setConnectTimeout(10000)            .setRetryAttempts(3)            .setRetryInterval(1500);        return Redisson.create(config);    &#125;&#125;

3. 线程池配置@Configurationpublic class ThreadPoolConfig &#123;        @Bean    public ThreadPoolExecutor seckillThreadPool() &#123;        return new ThreadPoolExecutor(            10,                      // corePoolSize            50,                      // maximumPoolSize            60,                      // keepAliveTime            TimeUnit.SECONDS,            new LinkedBlockingQueue&lt;&gt;(10000),  // workQueue            new ThreadFactoryBuilder().setNameFormat(&quot;seckill-%d&quot;).build(),            new ThreadPoolExecutor.CallerRunsPolicy()  // 拒绝策略        );    &#125;&#125;

八、面试加分点1. 秒杀系统优化路径秒杀系统优化演进：V1.0 裸奔版 → 直接操作数据库 → QPS: 500V2.0 缓存版 → Redis预减库存 → QPS: 2000V3.0 异步版 → MQ异步下单 → QPS: 10000V4.0 完整版 → 多级缓存+限流+异步 → QPS: 50000

2. 高并发设计原则高并发设计原则：1. 削峰填谷：使用MQ异步处理2. 多级缓存：本地缓存+分布式缓存3. 读写分离：主库写，从库读4. 分库分表：数据水平拆分5. 服务降级：非核心服务降级6. 熔断限流：保护系统不被压垮7. 灰度发布：降低发布风险8. 监控告警：实时发现问题

3. 热点Key解决方案总结热点Key解决方案：1. 本地缓存：Caffeine缓存热点数据2. 二级缓存：Redis + 本地缓存3. 热点预热：系统启动时加载热点数据4. 自动发现：基于访问频率识别热点Key5. 数据分片：将热点数据分散到多个节点6. CDN加速：静态资源使用CDN

总结高并发高可用是互联网公司的核心竞争力，掌握这些知识不仅能应对面试，还能设计出稳定的高并发系统。核心要点：

秒杀系统：库存预减、异步下单、防超卖、防作弊
多级缓存：本地缓存分布式缓存、热点Key处理
限流降级：令牌桶限流、业务降级、非核心服务降级
灰度发布：基于用户的路由策略、价值和风险评估
监控告警：完善的指标监控和告警机制
问题排查：快速定位和解决生产问题

这些都是面试中高频问到的问题，一定要深入理解并能说出落地实现。在实际项目中，需要根据业务场景选择合适的技术方案，平衡性能、可用性和成本。
